        [HttpGet]
        public ActionResult Index()
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            return View();
        }

        public ActionResult Voltar()
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            return RedirectToAction("MontarTelaDashboardCadastros", "BaseAdmin");
        }


        [HttpPost]
        public JsonResult BuscaNomeRazao(String nome)
        {
            Int32 isRazao = 0;
            List<Hashtable> listResult = new List<Hashtable>();
            Int32 idAss = (Int32)Session["IdAssinante"];
            USUARIO usuario = (USUARIO)Session["UserCredentials"];

            List<PACIENTE> clientes = baseApp.GetAllItens(idAss);
            Session["Pacientes"] = clientes;

            if (nome != null)
            {
                List<PACIENTE> lstCliente = clientes.Where(x => x.PACI_NM_NOME != null && x.PACI_NM_NOME.ToLower().Contains(nome.ToLower())).ToList<PACIENTE>();

                if (lstCliente == null || lstCliente.Count == 0)
                {
                    isRazao = 1;
                    lstCliente = clientes.Where(x => x.PACI_NM_SOCIAL != null).ToList<PACIENTE>();
                    lstCliente = lstCliente.Where(x => x.PACI_NM_SOCIAL.ToLower().Contains(nome.ToLower())).ToList<PACIENTE>();
                }

                if (usuario.PERFIL.PERF_SG_SIGLA != "ADM")
                {
                    lstCliente = lstCliente.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                }

                if (lstCliente != null)
                {
                    foreach (var item in lstCliente)
                    {
                        Hashtable result = new Hashtable();
                        result.Add("id", item.PACI__CD_ID);
                        if (isRazao == 0)
                        {
                            result.Add("text", item.PACI_NM_NOME);
                        }
                        else
                        {
                            result.Add("text", item.PACI_NM_NOME + " (" + item.PACI_NM_SOCIAL + ")");
                        }
                        listResult.Add(result);
                    }
                }
            }
            return Json(listResult);
        }


        [HttpGet]
        public ActionResult MontarTelaPaciente()
        {
            try
            {
                DateTime hoje = DateTime.Now;
                String x = hoje.Humanize();

                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_ACESSO_PACIENTE == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente";
                        return RedirectToAction("MontarTelaPaciente", "Paciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Dashboard Inicial";
                Session["ListaAvisoAtivo"] = null;

                // Carrega listas
                List<PACIENTE> forns = CarregaPaciente();
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                CONFIGURACAO_ANAMNESE confAna = CarregaConfiguracaoAnamnese();
                if (Session["ListaPacienteBase"] == null)
                {
                    listaMaster = CarregaPacienteUltimo();
                    if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                    {
                        listaMaster = listaMaster.ToList();
                    }
                    else
                    {
                        listaMaster = listaMaster.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                    }
                    Session["ListaPacienteBase"] = listaMaster;
                }
                ViewBag.Listas = (List<PACIENTE>)Session["ListaPacienteBase"];
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/6/Ajuda6_1.pdf";


                // Trata mensagens
                if (Session["MensPaciente"] != null)
                {
                    // Mensagem
                    if ((Int32)Session["MensPaciente"] == 61)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                    if ((Int32)Session["MensPaciente"] == 50)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0512", CultureInfo.CurrentCulture));
                    }
                }

                // Pacientes
                List<PACIENTE> listaCli = CarregaPaciente().Where(p => p.PACI_IN_ATIVO == 1).ToList();
                if (usuario.PERFIL.PERF_SG_SIGLA != "ADM" & usuario.PERFIL.PERF_IN_VISAO_GERAL == 0)
                {
                    listaCli = listaCli.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                }
                Int32 totalCli = listaCli.Count;
                ViewBag.Pacientes = totalCli;

                List<PACIENTE> listaBase = listaCli.Where(p => p.PACI_DT_PREVISAO_RETORNO != null).ToList();
                List<PACIENTE> listaAtraso = listaBase.Where(p => p.PACI_DT_PREVISAO_RETORNO.Value.AddMonths(conf.CONF_IN_PACIENTE_ATRASO.Value) < DateTime.Today.Date).ToList();
                ViewBag.Atrasos = listaAtraso.Count;
                Session["PacientesAtraso"] = listaAtraso;
                Session["Atrasos"] = listaAtraso.Count;
                ViewBag.AtrasoDias = conf.CONF_IN_PACIENTE_ATRASO.ToString();

                List<PACIENTE> listaAusencia = listaBase.Where(p => p.PACI_DT_PREVISAO_RETORNO.Value.AddMonths(conf.CONF_IN_PACIENTE_AUSENCIA.Value) < DateTime.Today.Date).ToList();
                ViewBag.Ausencia = listaAusencia.Count;
                Session["PacientesAusente"] = listaAusencia;
                Session["Ausencia"] = listaAusencia.Count;
                ViewBag.AusenciaDias = conf.CONF_IN_PACIENTE_AUSENCIA.ToString();

                // Consultas
                List<PACIENTE_CONSULTA> cons = baseApp.GetAllConsultas(idAss);
                if (usuario.PERFIL.PERF_SG_SIGLA != "ADM" & usuario.PERFIL.PERF_IN_VISAO_GERAL == 0)
                {
                    cons = cons.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                }
                List<PACIENTE_CONSULTA> consultas = cons.Where(p => p.PACO_DT_CONSULTA == DateTime.Today.Date & p.PACO_IN_ATIVO == 1 & p.PACO_IN_CONFIRMADA == 1).ToList();
                ViewBag.Consultas = consultas.OrderBy(p => p.PACO_HR_INICIO).ToList();
                ViewBag.NumConsultas = consultas.Count;

                List<PACIENTE_CONSULTA> naoEncerradas = cons.Where(p => p.PACO_DT_CONSULTA < DateTime.Today.Date & p.PACO_IN_ATIVO == 1 & p.PACO_IN_CONFIRMADA == 1 & p.PACO_IN_ENCERRADA == 0).ToList();
                ViewBag.NaoEncerradas = naoEncerradas.OrderBy(p => p.PACO_HR_INICIO).ToList();
                ViewBag.NaoEncerradasNumero = naoEncerradas.Count;

                // Consultas por data
                Session["ListaConsultaData"] = null;
                List<DateTime> datas = cons.Select(p => p.PACO_DT_CONSULTA.Date).Distinct().ToList();
                DateTime limite = DateTime.Today.Date.AddDays(-30);
                DateTime limiteSuperior = DateTime.Today.Date.AddDays(30);
                if ((Int32)Session["PacienteAlterada"] == 1 || (Int32)Session["FlagPaciente"] == 1 || Session["ListaConsultaData"] == null)
                {
                    datas.Sort((i, j) => i.Date.CompareTo(j.Date));
                    List<ModeloViewModel> lista = new List<ModeloViewModel>();
                    foreach (DateTime item in datas)
                    {
                        if (item.Date > limite & item.Date < limiteSuperior)
                        {
                            Int32 conta = cons.Where(p => p.PACO_DT_CONSULTA.Date == item.Date).Count();
                            ModeloViewModel mod = new ModeloViewModel();
                            mod.DataEmissao = item;
                            mod.Valor = conta;
                            lista.Add(mod);
                        }
                    }
                    ViewBag.ListaConsultaData = lista;
                    Session["ListaConsultaData"] = lista;
                    Session["NumListaConsultaData"] = lista.Count;
                    ViewBag.NumListaConsultaData = lista.Count;
                }
                else
                {
                    ViewBag.ListaConsultaData = (List<ModeloViewModel>)Session["ListaConsultaData"];
                    ViewBag.NumListaConsultaData = ((List<ModeloViewModel>)Session["ListaConsultaData"]).Count;
                }

                // Aniversariantes do dia
                if ((Int32)Session["PacienteAlterada"] == 1 || (Int32)Session["FlagPaciente"] == 1 || Session["ListaPacienteAnivDia"] == null)
                {
                    List<PACIENTE> listaCli1 = listaCli.Where(p => p.PACI_DT_NASCIMENTO != null).ToList();
                    List<ModeloViewModel> listaAniv = new List<ModeloViewModel>();
                    List<PACIENTE> aniv = listaCli1.Where(p => p.PACI_DT_NASCIMENTO.Value.Month == DateTime.Today.Month & p.PACI_DT_NASCIMENTO.Value.Day == DateTime.Today.Day).ToList();
                    Session["ListaAnivDia"] = aniv;
                    foreach (PACIENTE item in aniv)
                    {
                        ModeloViewModel mod = new ModeloViewModel();
                        mod.Nome = item.PACI_NM_NOME;
                        mod.DataEmissao = item.PACI_DT_NASCIMENTO.Value;
                        mod.Valor1 = item.PACI__CD_ID;
                        mod.Nome1 = item.PACI_NM_EMAIL;
                        listaAniv.Add(mod);
                    }
                    ViewBag.ListaPacienteAnivDia = listaAniv;
                    Session["ListaPacienteAnivDia"] = listaAniv;
                    ViewBag.ListaPacienteAnivDiaConta = listaAniv.Count;
                }
                else
                {
                    ViewBag.ListaPacienteAnivDia = (List<ModeloViewModel>)Session["ListaPacienteAnivDia"];
                    ViewBag.ListaPacienteAnivDiaConta = ((List<ModeloViewModel>)Session["ListaPacienteAnivDiaConta"]).Count;
                }

                // Informações prévias
                if ((Int32)Session["PacienteAlterada"] == 1 || (Int32)Session["FlagPaciente"] == 1 || Session["ListaPrevia"] == null)
                {
                    List<ModeloViewModel> lista4 = new List<ModeloViewModel>();
                    List<RESPOSTA_CONSULTA> resp = baseApp.GetAllResposta(idAss);
                    resp = resp.Where(p => p.RECO_IN_ATIVO == 1 & p.RECO_IN_VISTO == 0).ToList();
                    foreach (RESPOSTA_CONSULTA item in resp)
                    {
                        ModeloViewModel mod = new ModeloViewModel();
                        mod.DataEmissao = item.PACIENTE_CONSULTA.PACO_DT_CONSULTA;
                        mod.Nome = (baseApp.GetItemById(item.PACI_CD_ID.Value)).PACI_NM_NOME;
                        mod.Valor1 = item.RECO_CD_ID;
                        mod.Valor2 = item.PACI_CD_ID.Value;
                        lista4.Add(mod);
                    }
                    ViewBag.ListaPrevia = lista4;
                    Session["ListaPrevia"] = lista4;
                }
                else
                {
                    ViewBag.ListaPrevia = (List<ModeloViewModel>)Session["ListaPrevia"];
                }

                // Gera aviso de estoque baixo
                if (conf.CONF_IN_AVISO_ESTOQUE != 0)
                {
                    List<PRODUTO> listaProd = CarregarProduto();
                    listaProd = listaProd.Where(p => p.PROD_VL_ESTOQUE_ATUAL < p.PROD_VL_ESTOQUE_MINIMO).ToList();
                    if (listaProd.Count() > 0)
                    {
                        foreach (PRODUTO item in listaProd)
                        {
                            Int32 cria = 0;
                            List<AVISO_LEMBRETE> avs1 = CarregarAviso();
                            List<AVISO_LEMBRETE> avs = avs1.Where(p => p.PROD_CD_ID == item.PROD_CD_ID & p.AVIS_DT_CRIACAO.Value.Date == DateTime.Today.Date).ToList();
                            cria = avs.Count() > 0 ? 0 : 1;

                            if (cria == 0)
                            {
                                List<AVISO_LEMBRETE> avs2 = avs1.Where(p => p.PROD_CD_ID == item.PROD_CD_ID & p.AVIS_DT_CRIACAO.Value.Date < DateTime.Today.Date.AddDays(-5)).ToList();
                                if (conf.CONF_IN_AVISO_ESTOQUE == 1)
                                {
                                    cria = avs2.Count() > 0 ? 1 : 0;
                                }
                            }
                            else if (cria == 1)
                            {
                                AVISO_LEMBRETE aviso = new AVISO_LEMBRETE();
                                aviso.ASSI_CD_ID = idAss;
                                aviso.AVIS_DS_AVISO = "Material/Produto com estoque abaixo do mínimo ou zerado." + Environment.NewLine + "Produto: " + item.PROD_NM_NOME + Environment.NewLine + "Estoque Atual: " + item.PROD_VL_ESTOQUE_ATUAL.ToString() + Environment.NewLine + "Estoque Mínimo: " + item.PROD_VL_ESTOQUE_MINIMO.ToString();
                                aviso.AVIS_DT_AVISO = DateTime.Today.Date;
                                aviso.AVIS_DT_CRIACAO = DateTime.Now;
                                aviso.AVIS_IN_ATIVO = 1;
                                aviso.AVIS_IN_CIENTE = 0;
                                aviso.AVIS_IN_SISTEMA = 6;
                                aviso.AVIS_NM_TITULO = "Material/Produto com estoque abaixo do mínimo";
                                aviso.PROD_CD_ID = item.PROD_CD_ID;
                                aviso.USUA_CD_ID = usuario.USUA_CD_ID;
                                Int32 voltaAviso = aviApp.ValidateCreate(aviso);
                            }
                        }
                        Session["AvisoAlterada"] = 1;
                    }
                }

                // Avisos ativos
                ViewBag.ListaAvisoAtivo = null;
                if (Session["ListaAvisoAtivo"] == null)
                {
                    List<ModeloViewModel> listaAviso = new List<ModeloViewModel>();
                    List<AVISO_LEMBRETE> avisoLista = CarregarAviso().Where(p => p.AVIS_IN_ATIVO == 1 & p.USUA_CD_ID == usuario.USUA_CD_ID).OrderByDescending(p => p.AVIS_DT_CRIACAO).Take(4).ToList();
                    avisoLista = avisoLista.Where(p => p.AVIS_IN_CIENTE == 0).ToList();
                    foreach (AVISO_LEMBRETE item in avisoLista)
                    {
                        ModeloViewModel mod = new ModeloViewModel();
                        mod.Nome = item.AVIS_NM_TITULO;
                        mod.DataEmissao = item.AVIS_DT_AVISO.Value;
                        mod.Valor1 = item.AVIS_IN_CIENTE.Value;
                        mod.Valor2 = item.AVIS_CD_ID;
                        listaAviso.Add(mod);
                    }
                    ViewBag.ListaAvisoAtivo = listaAviso;
                    Session["ListaAvisoAtivo"] = listaAviso;
                }
                else
                {
                    ViewBag.ListaAvisoAtivo = (List<ModeloViewModel>)Session["ListaAvisoAtivo"];
                    ViewBag.ListaAvisoAtivo = ((List<ModeloViewModel>)Session["ListaAvisoAtivo"]).Count;
                }

                // Atualiza locações
                List<LOCACAO> locas = CarregarLocacao().Where(p => p.LOCA_IN_STATUS == 1).ToList();
                foreach (LOCACAO item in locas)
                {
                    // Verifica data
                    Int32 atual = 0;
                    if (item.LOCA_DT_FINAL.Value.Date <= DateTime.Today.Date)
                    {
                        atual = 1;
                    }
                    else
                    {
                        TimeSpan diferenca = (item.LOCA_DT_FINAL.Value).Subtract(DateTime.Today.Date);
                        Int32 diasCompletos = diferenca.Days;
                        if (diasCompletos <= 30)
                        {
                            atual = 1;
                        }
                    }

                    // Atualiza locacao
                    if (atual == 1)
                    {
                        LOCACAO loca = locApp.GetItemById(item.LOCA_CD_ID);
                        loca.LOCA_IN_STATUS = 3;
                        Int32 volta = locApp.ValidateEdit(loca, item, usuario);
                    }
                }

                // Atualiza parcelas vencidas
                List<LOCACAO_PARCELA> parcs = CarregarParcelas().Where(p => p.LOPA_IN_QUITADA == 0 & p.LOPA_DT_VENCIMENTO.Value.Date < DateTime.Today.Date).ToList();
                foreach (LOCACAO_PARCELA item in parcs)
                {
                    // Atualiza parcela
                    LOCACAO loca = locApp.GetItemById(item.LOCA_CD_ID);
                    LOCACAO_PARCELA parc = locApp.GetParcelaById(item.LOPA_CD_ID);
                    Decimal? antes = parc.LOPA_VL_VALOR;
                    parc.LOPA_VL_VALOR = loca.LOCA_VL_VALOR_ATRASO;
                    parc.LOPA_VL_JUROS = loca.LOCA_VL_VALOR_ATRASO - antes;
                    Int32 volta = locApp.ValidateEditParcela(parc);
                }

                // Mensagens do Fabricante
                ViewBag.MensFab = null;
                ViewBag.MensFabPrim = null;
                ViewBag.NumSlides = 0;
                List<MENSAGEM_FABRICANTE> mensFab = usuApp.GetAllMensFab(idAss).ToList();
                ViewBag.ListasFabricante = mensFab;
                ViewBag.NumListasFabricante = mensFab.Count;

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 1)
                    {
