                    Int32 voltaG = baseApp.ValidateEdit(item, item);

                    // Grava historico
                    PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                    hist.ASSI_CD_ID = usuario.ASSI_CD_ID;
                    hist.USUA_CD_ID = usuario.USUA_CD_ID;
                    hist.PACI_CD_ID = item.PACI__CD_ID;
                    hist.PAHI_DT_DATA = DateTime.Now;
                    hist.PAHI_IN_TIPO = 1;
                    hist.PAHI_IN_CHAVE = item.PACI__CD_ID;
                    hist.PAHI_NM_OPERACAO = "Paciente - Inclusão";
                    hist.PAHI_DS_DESCRICAO = "Inclusão do paciente " + item.PACI_NM_NOME;
                    Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);

                    // Mensagem de inclusão
                    String frase = "O paciente " + item.PACI_NM_NOME.ToUpper() + " foi incluído com sucesso.";
                    if (vm.CRIA_CONSULTA == 1)
                    {
                        if (voltaUtil > 0)
                        {
                            frase += " Não foi criada a consulta. Crie manualmente.";
                        }
                        if (voltaUtil == 1)
                        {
                            frase += " A data especificada não é um dia útil.";
                        }
                        else if (voltaUtil == 2)
                        {
                            frase += " A hora da consulta está fora do horário útil.";
                        }
                        else if (voltaUtil == 3)
                        {
                            frase += " A hora da consulta está sobrepondo o intervalo de descanso.";
                        }
                        else if (voltaUtil == 4)
                        {
                            frase += " A hora da consulta está sobrepondo a consulta já marcada.";
                        }
                        else
                        {
                            frase += "A consulta prevista foi marcada";
                        }
                    }
                    Session["MsgCRUD"] = frase;
                    Session["MensPaciente"] = 61;

                    // Trata retorno
                    if ((Int32)Session["VoltaPaciente"] == 99)
                    {
                        return RedirectToAction("IncluirMensagemEMail", "Mensagem");
                    }
                    if ((Int32)Session["VoltaPaciente"] == 3)
                    {
                        Session["VoltaPaciente"] = 0;
                        return RedirectToAction("IncluirPaciente", "Paciente");
                    }
                    Session["NivelPaciente"] = 1;
                    Session["ListaConsultasGeral"] = null;
                    Session["ConsultaAlterada"] = 1;

                    if (conf.CONF_IN_INCLUIR_PACIENTE_SEGUE == 0)
                    {
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                    return RedirectToAction("IncluirPaciente");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "epront", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

