                    // Critica tamanho
                    if (vm.MENS_TX_SMS.Length > 300)
                    {
                        vm.MENS_TX_SMS = vm.MENS_TX_SMS.Substring(0, 299);
                    }

                    // Executa a operação
                    USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
