                Int32 voltaX = grava.GravarLogExcecao(ex, "Modelos", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return null;
            }
        }
        [HttpGet]
        [ValidateInput(false)]
        public ActionResult EnviarMailAniversario()
        {
            try
            {
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                USUARIO usuario = (USUARIO)Session["UserCredentials"];

                // Verifica possibilidade
                List<PACIENTE> clientes = (List<PACIENTE>)Session["ListaAnivDia"];
                ViewBag.Mail = 0;
                Int32 num = CarregaMensagemEnviada().Where(p => p.MEEN_DT_DATA_ENVIO.Value.Month == DateTime.Today.Date.Month & p.MEEN_DT_DATA_ENVIO.Value.Year == DateTime.Today.Date.Year & p.MEEN_IN_TIPO == 1).ToList().Count;
                num += clientes.Count;
                if ((Int32)Session["NumEMail"] <= num)
                {
                    ViewBag.Mail = 1;
                }

                // Mensagens
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 333)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0401", CultureInfo.CurrentCulture));
                    }

                }

                // Carrega listas
                List<MensagemViewModel> listaAniv = new List<MensagemViewModel>();
