                tipo.Add(new SelectListItem() { Text = "Texto Digitado", Value = "1" });
                tipo.Add(new SelectListItem() { Text = "Modelo de Mensagem", Value = "3" });
                tipo.Add(new SelectListItem() { Text = "Arquivo HTML", Value = "2" });
                ViewBag.Tipos = new SelectList(tipo, "Value", "Text");

                // Checa controle
                CONTROLE_MENSAGEM cm = cmApp.GetItemByDate(DateTime.Today.Date, idAss);
                if (cm != null)
                {
                    if (cm.COME_IN_ANIVERSARIO == 1)
                    {
                        ViewBag.Mail = 2;
                    }
                }

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_ANIVERSARIO", "Paciente", "EnviarMailAniversario");

                // Monta view
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/6/Ajuda6_9.pdf";
                Session["MensPaciente"] = null;
                mensVolta.MENS_DT_CRIACAO = DateTime.Today.Date;
                mensVolta.MENS_IN_TIPO = 1;
                mensVolta.MENS_IN_TIPO_EMAIL = 1;
                mensVolta.TIPO_ENVIO = 1;
                mensVolta.MENS_NM_CAMPANHA = "Mensagem de Aniversário";
                mensVolta.MENS_NM_NOME = "Aniversário";
                return View(mensVolta);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return null;
            }
        }

        [HttpPost]
        [ValidateInput(false)]
        public async Task<ActionResult> EnviarMailAniversario(MensagemViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            Int32 idAss = (Int32)Session["IdAssinante"];
            USUARIO usuario = (USUARIO)Session["UserCredentials"];
            ViewBag.ListaPacienteAnivDia = (List<ModeloViewModel>)Session["ListaPacienteAnivDia"];
            ViewBag.ListaPacienteAnivDiaConta = ((List<ModeloViewModel>)Session["ListaPacienteAnivDia"]).Count;

            ViewBag.Modelos = new SelectList(CarregarModelosHtml(), "Value", "Text");
            ViewBag.Templates = new SelectList(CarregarModeloEMail().Where(p => p.TEEM_IN_HTML == 1).OrderBy(p => p.TEEM_NM_NOME), "TEEM_CD_ID", "TEEM_NM_NOME");
            List<SelectListItem> tipo = new List<SelectListItem>();
            tipo.Add(new SelectListItem() { Text = "Texto Digitado", Value = "1" });
            tipo.Add(new SelectListItem() { Text = "Modelo de Mensagem", Value = "3" });
            tipo.Add(new SelectListItem() { Text = "Arquivo HTML", Value = "2" });
            ViewBag.Tipos = new SelectList(tipo, "Value", "Text");
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização
                    vm.MENS_TX_TEXTO = CrossCutting.UtilitariosGeral.CleanStringGeral(vm.MENS_TX_TEXTO);
                    vm.MENS_NM_LINK = CrossCutting.UtilitariosGeral.CleanStringLink(vm.MENS_NM_LINK);

                    // Executa a operação
                    USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
                    List<ModeloViewModel> lista = (List<ModeloViewModel>)Session["ListaPacienteAnivDia"];

                    Int32 volta = await ProcessaEnvioEMailAniversario(vm, lista, usuarioLogado);

                    // Mensagens
                    if (volta == 1)
                    {
                        Session["MensPaciente"] = 333;
                        return View(vm);
                    }

                    // Grava controle
                    CONTROLE_MENSAGEM cm = cmApp.GetItemByDate(DateTime.Today.Date, idAss);
                    if (cm == null)
                    {
                        CONTROLE_MENSAGEM cm1 = new CONTROLE_MENSAGEM();
                        cm1.ASSI_CD_ID = idAss;
                        cm1.COME_IN_SISTEMA = 6;
                        cm1.COME_DT_DATA = DateTime.Today.Date;
                        cm1.COME_IN_ANIVERSARIO = 1;
                        Int32 voltax = cmApp.ValidateCreate(cm1, usuario);
                    }
                    else
                    {
                        cm.COME_IN_ANIVERSARIO = 1;
                        Int32 voltay = cmApp.ValidateEdit(cm, cm, usuario);
                    }

                    // Mensagem
                    if ((Int32)Session["TotErros"] == 0)
                    {
                        Session["MsgCRUD"] = "As mensagens de aniversário de " + DateTime.Today.Date.ToShortDateString() + " foram enviadas com sucesso. Foram enviadas " + ((Int32)Session["TotEnvios"]).ToString() + " mensagens de um total de " + ((Int32)Session["TotMensagens"]).ToString() + " mensagens";
                    }
                    else
                    {
                        Session["MsgCRUD"] = "As mensagens de aniversário de " + DateTime.Today.Date.ToShortDateString() + " foram enviadas com falhas. Foram enviadas " + ((Int32)Session["TotEnvios"]).ToString() + " mensagens em um total de " + ((Int32)Session["TotMensagens"]).ToString() + " mensagens";
                    }
                    Session["MensPaciente"] = 888;

                    // Retorno
                    Session["NivelPaciente"] = 1;
                    if ((Int32)Session["VoltaAniversario"] == 1)
                    {
                        return RedirectToAction("MontarTelaCentralPaciente");
                    }
                    return RedirectToAction("VoltarBasePaciente");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }
        [NonAction]
        public List<SelectListItem> CarregarModelosHtml()
        {
            Int32 idAss = (Int32)Session["IdAssinante"];
            String caminho = "/TemplateEMail/Modelos/" + idAss.ToString() + "/";
            String path = Path.Combine(Server.MapPath(caminho));
            String[] files = Directory.GetFiles(path, "*.html");
            List<SelectListItem> mod = new List<SelectListItem>();
            foreach (String file in files)
            {
                mod.Add(new SelectListItem() { Text = System.IO.Path.GetFileNameWithoutExtension(file), Value = file });
            }

            return mod;
        }

        [HttpGet]
