                Session["IdPaciente"] = id;
                Session["PacienteAntes"] = item;

                // Carrega Listas
                List<PACIENTE_PRESCRICAO> listaPrescricao = item.PACIENTE_PRESCRICAO.Where(p => p.PAPR_IN_ATIVO == 1).ToList();
                Session["ListaPrescricao"] = listaPrescricao;
