                Session["TemFisico"] = temFisico;

                // Carrega acompanhamento
                if (temAnamnese == 1)
                {
                    PACIENTE_ANAMNESE ana = baseApp.GetAnamneseById((Int32)Session["IdAnamnese"]);
                    List<PACIENTE_ANAMNESE_ANOTACAO> acom = ana.PACIENTE_ANAMNESE_ANOTACAO.Where(p => p.PAAA_IN_ATIVO == 1).ToList();
                    ViewBag.Acompanhamento = acom;
                }
                else
                {
                    ViewBag.Acompanhamento = null;
                }

                // Checa faixa de preco
                DateTime? faixa = item.PACI_DT_PRECO;
                Int32 avisoFaixa = 0;
                if (faixa !=  null)
                {
                    TimeSpan? diferenca = DateTime.Today.Date - faixa;
                    Int32? totalDeDias = (Int32)diferenca.Value.TotalDays;
                    if (totalDeDias > conf.CONF_IN_VALIDADE_FAIXA)
                    {
                        avisoFaixa = 1;
                    }
                }
                ViewBag.AvisoFaixa = avisoFaixa;

                // Carrega questionario Berlim
                QUESTIONARIO_BERLIM berlin = item.QUESTIONARIO_BERLIM.FirstOrDefault();
                vm.QUBE_IN_CANSACO = berlin.QUBE_IN_CANSACO;
                vm.QUBE_IN_CANSACO_ACORDADO = berlin.QUBE_IN_CANSACO_ACORDADO;
                vm.QUBE_IN_CATEGORIA_1 = berlin.QUBE_IN_CATEGORIA_1;
                vm.QUBE_IN_CATEGORIA_2 = berlin.QUBE_IN_CATEGORIA_2;
                vm.QUBE_IN_CATEGORIA_3 = berlin.QUBE_IN_CATEGORIA_3;
                vm.QUBE_IN_COCHILO = berlin.QUBE_IN_COCHILO;
                vm.QUBE_IN_FREQUENCIA_RONCO = berlin.QUBE_IN_FREQUENCIA_RONCO;
                vm.QUBE_IN_INCOMODA_RONCO = berlin.QUBE_IN_INCOMODA_RONCO;
                vm.QUBE_IN_PARA_RESPIRA = berlin.QUBE_IN_PARA_RESPIRA;
                vm.QUBE_IN_PONTUACAO = berlin.QUBE_IN_PONTUACAO;
                vm.QUBE_IN_PRESSAO = berlin.QUBE_IN_PRESSAO;
                vm.QUBE_IN_RONCO = berlin.QUBE_IN_RONCO;
                vm.QUBE_IN_TIPO_RONCO = berlin.QUBE_IN_TIPO_RONCO;
                vm.QUBE_NR_IMC = berlin.QUBE_NR_IMC;

                // Carrega questionario Epworth
                QUESTIONARIO_EPWORTH epwort = item.QUESTIONARIO_EPWORTH.FirstOrDefault();
                vm.QUEP_IN_ALMOCO = epwort.QUEP_IN_ALMOCO;
                vm.QUEP_IN_CARRO = epwort.QUEP_IN_CARRO;
                vm.QUEP_IN_CONVERSA = epwort.QUEP_IN_CONVERSA;
                vm.QUEP_IN_DEITADO = epwort.QUEP_IN_DEITADO;
                vm.QUEP_IN_INATIVO = epwort.QUEP_IN_INATIVO;
                vm.QUEP_IN_LIVRO = epwort.QUEP_IN_LIVRO;
                vm.QUEP_IN_RESULTADO = epwort.QUEP_IN_RESULTADO;
                vm.QUEP_IN_TV = epwort.QUEP_IN_TV;
                vm.QUEP_IN_VOLANTE = epwort.QUEP_IN_VOLANTE;

                QUESTIONARIO_STOPBANG bang1 = item.QUESTIONARIO_STOPBANG.FirstOrDefault();
                vm.QUSB_DS_PONTUACAO = bang1.QUSB_DS_PONTUACAO;
                vm.QUSB_IN_CANSADO = bang1.QUSB_IN_CANSADO;
                vm.QUSB_IN_IDADE = bang1.QUSB_IN_IDADE;
                vm.QUSB_IN_IMC = bang1.QUSB_IN_IMC;
                vm.QUSB_IN_MASCULINO = bang1.QUSB_IN_MASCULINO;
                vm.QUSB_IN_OBSERVA = bang1.QUSB_IN_OBSERVA;
                vm.QUSB_IN_PESCOCO = bang1.QUSB_IN_PESCOCO;
                vm.QUSB_IN_PRESSAO = bang1.QUSB_IN_PRESSAO;
                vm.QUSB_IN_RONCO = bang1.QUSB_IN_RONCO;
                vm.QUBE_IN_PONTUACAO = bang1.QUSB_IN_PONTUACAO;
                vm.QUSB_DS_PONTUACAO = bang1.QUSB_DS_PONTUACAO;

                String TextoPescocoGrosso = "Para homens, o colarinho da sua camisa é de 43 cm ou mais? Para mulheres, o colarinho da sua camisa é de 41 cm ou mais?";
                ViewBag.Pescoco = TextoPescocoGrosso;

                // Verifica abas
                Session["AbaVac"] = conf.CONF_IN_ABA_VACINA;
                Session["AbaAt"] = conf.CONF_IN_ABA_ATESTADO;
                Session["AbaSol"] = conf.CONF_IN_ABA_SOLICITACAO;
                Session["AbaEx"] = conf.CONF_IN_ABA_EXAME;
                Session["AbaPr"] = conf.CONF_IN_ABA_PRESCRICAO;
                Session["AbaLoc"] = conf.CONF_IN_ABA_LOCACAO;
                Session["EscondeAba"] = 0;

                if (conf.CONF_IN_ABA_VACINA == 0 || conf.CONF_IN_ABA_ATESTADO == 0 ||conf.CONF_IN_ABA_SOLICITACAO == 0 ||conf.CONF_IN_ABA_EXAME == 0 ||conf.CONF_IN_ABA_PRESCRICAO == 0 ||conf.CONF_IN_ABA_LOCACAO == 0)
                {
                    Session["EscondeAba"] = 1;
                }
                Session["VACO"] = vm.VACO_CD_ID;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_EDITAR", "Paciente", "EditarPaciente");

                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        [ValidateInput(false)]
        public ActionResult EditarPaciente(PacienteViewModel vm)
        {
            // Preparação
            Int32 idAss = (Int32)Session["IdAssinante"];
            USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
            List<UF> uFs = CarregaUF();
            ViewBag.Tipos = new SelectList(CarregaCatPaciente(), "TIPA_CD_ID", "TIPA_NM_NOME");
            ViewBag.Sexo = new SelectList(CarregaSexo(), "SEXO_CD_ID", "SEXO_NM_NOME");
            ViewBag.Raca = new SelectList(baseApp.GetAllRaca(), "RACA_CD_ID", "RACA_NM_NOME");
            ViewBag.Cor = new SelectList(CarregaCor(), "COR1_CD_ID", "COR1_NM_NOME");
            ViewBag.EstadoCivil = new SelectList(CarregaEstadoCivil(), "ESCI_CD_ID", "ESCI_NM_NOME");
            ViewBag.Convenio = new SelectList(CarregaConvenio(), "CONV_CD_ID", "CONV_NM_NOME");
            ViewBag.UF = new SelectList(uFs, "UF_CD_ID", "UF_SG_SIGLA");
            List<USUARIO> usuarios = CarregaUsuario();
            ViewBag.Usuarios = new SelectList(usuarios, "USUA_CD_ID", "USUA_NM_NOME");
            ViewBag.Nacionalidades = new SelectList(CarregaNacionalidade(), "NACI_CD_ID", "NACI_NM_PAIS");
            ViewBag.Municipios = new SelectList(CarregaMunicipio(), "MUNI_CD_ID", "MUNI_NM_NOME");
            ViewBag.GrauInstrucao = new SelectList(CarregaGrauInstrucao(), "GRAU_CD_ID", "GRAU_NM_NOME");
            List<SelectListItem> menor = new List<SelectListItem>();
            menor.Add(new SelectListItem() { Text = "Sim", Value = "1" });
            menor.Add(new SelectListItem() { Text = "Não", Value = "0" });
            ViewBag.Menor = new SelectList(menor, "Value", "Text");
            List<SelectListItem> anam = new List<SelectListItem>();
            anam.Add(new SelectListItem() { Text = "Padrão - Segmentada", Value = "1" });
            anam.Add(new SelectListItem() { Text = "Contínua", Value = "2" });
            ViewBag.Anamnese = new SelectList(anam, "Value", "Text");
            List<SelectListItem> ficha = new List<SelectListItem>();
            ficha.Add(new SelectListItem() { Text = "Sim", Value = "1" });
            ficha.Add(new SelectListItem() { Text = "Não", Value = "0" });
            ViewBag.Ficha = new SelectList(ficha, "Value", "Text");
            List<SelectListItem> formato = new List<SelectListItem>();
            formato.Add(new SelectListItem() { Text = "Por Data", Value = "1" });
            formato.Add(new SelectListItem() { Text = "Livre", Value = "0" });
            ViewBag.Formato = new SelectList(formato, "Value", "Text");
            ViewBag.Perfil = usuarioLogado.PERFIL.PERF_SG_SIGLA;
            List<VALOR_CONSULTA> tipos = CarregaTipoConsulta();
            ViewBag.TipoConsulta = new SelectList(tipos, "VACO_CD_ID", "VACO_NM_EXIBE");
            List<SelectListItem> simNao = new List<SelectListItem>();
            simNao.Add(new SelectListItem() { Text = "Sim", Value = "1" });
            simNao.Add(new SelectListItem() { Text = "Não", Value = "0" });
            ViewBag.SimNao = new SelectList(simNao, "Value", "Text");

            List<SelectListItem> ufNatur = new List<SelectListItem>();
            List<SelectListItem> ufNatur1 = new List<SelectListItem>();
            foreach (UF uf in uFs)
            {
                ufNatur.Add(new SelectListItem() { Text = uf.UF_NM_NOME, Value = uf.UF_CD_ID.ToString() });
                ufNatur1.Add(new SelectListItem() { Text = uf.UF_NM_NOME, Value = uf.UF_CD_ID.ToString() });
            }
            ViewBag.UFNatur1 = new SelectList(ufNatur, "Value", "Text");
            ViewBag.UFNatur2 = new SelectList(ufNatur1, "Value", "Text");
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização
                    vm.PACI_NM_NOME = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_NOME);
                    vm.PACI_NR_CPF = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NR_CPF);
                    vm.PACI_NM_SOCIAL = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_SOCIAL);
                    vm.PACI_NM_PAI = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_PAI);
                    vm.PACI_NM_MAE = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_MAE);
                    vm.PACI_NR_CEP = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NR_CEP);
                    vm.PACI_NR_COMPLEMENTO = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NR_COMPLEMENTO);
                    vm.PACI_NM_ENDERECO = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_ENDERECO);
                    vm.PACI_NR_NUMERO = CrossCutting.UtilitariosGeral.CleanStringGeral(vm.PACI_NR_NUMERO);
                    vm.PACI_NM_BAIRRO = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_BAIRRO);
                    vm.PACI_NM_CIDADE = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_CIDADE);
                    vm.PACI_NM_PROFISSAO = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_PROFISSAO);
                    vm.PACI_NM_NATURALIDADE = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_NATURALIDADE);
                    vm.PACI_NM_NACIONALIDADE = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_NACIONALIDADE);
                    vm.PACI_NR_RG = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NR_RG);
                    vm.PACI_NR_TELEFONE = CrossCutting.UtilitariosGeral.CleanStringPhone(vm.PACI_NR_TELEFONE);
                    vm.PACI_NR_CELULAR = CrossCutting.UtilitariosGeral.CleanStringPhone(vm.PACI_NR_CELULAR);
                    vm.PACI_NM_EMAIL = CrossCutting.UtilitariosGeral.CleanStringMail(vm.PACI_NM_EMAIL);
                    vm.PACI_NR_MATRICULA = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NR_MATRICULA);
                    vm.PACI_NM_INDICACAO = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_NM_INDICACAO);
                    vm.PACI_TX_OBSERVACOES = CrossCutting.UtilitariosGeral.CleanStringDocto(vm.PACI_TX_OBSERVACOES);
                    vm.PACI__CD_ID = (Int32)Session["IdPaciente"];

                    // Criticas
                    if (vm.PACI_NM_NOME == null)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0527", CultureInfo.CurrentCulture));
                        return View(vm);
                    }
                    if (vm.PACI_DT_NASCIMENTO.Value.Date >= DateTime.Today.Date)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0531", CultureInfo.CurrentCulture));
                        return View(vm);
                    }

                    // Critica de tabelas auxiliares
                    if (vm.TIPA_CD_ID == 0)
                    {
                        vm.TIPA_CD_ID = CarregaCatPaciente().Where(p => p.TIPA_NM_NOME.Contains("Informad")).FirstOrDefault().TIPA_CD_ID;
                    }
                    if (vm.SEXO_CD_ID == null || vm.SEXO_CD_ID == 0)
                    {
                        vm.SEXO_CD_ID = CarregaSexo().Where(p => p.SEXO_NM_NOME.Contains("Informad")).FirstOrDefault().SEXO_CD_ID;
                    }
                    if (vm.COR1_CD_ID == null || vm.COR1_CD_ID == 0)
                    {
                        vm.COR1_CD_ID = CarregaCor().Where(p => p.COR1_NM_NOME.Contains("Informad")).FirstOrDefault().COR1_CD_ID;
                    }
                    if (vm.ESCI_CD_ID == null || vm.ESCI_CD_ID == 0)
                    {
                        vm.ESCI_CD_ID = CarregaEstadoCivil().Where(p => p.ESCI_NM_NOME.Contains("Informad")).FirstOrDefault().ESCI_CD_ID;
                    }
                    if (vm.GRAU_CD_ID == null || vm.GRAU_CD_ID == 0)
                    {
                        vm.GRAU_CD_ID = CarregaGrauInstrucao().Where(p => p.GRAU_NM_NOME.Contains("Informad")).FirstOrDefault().GRAU_CD_ID;
                    }

                    // Critica de padrao de consulta
                    if (vm.VACO_CD_ID == 0 || vm.VACO_CD_ID == null)
                    {
                        vm.VACO_CD_ID = tipos.Where(p => p.VACO_IN_PADRAO == 1).FirstOrDefault().VACO_CD_ID;
                    }

                    // Acerta dados
                    vm.PACI_DT_ALTERACAO = DateTime.Now;

                    // Serializa paciente
                    String json = JsonConvert.SerializeObject(vm);

                    // Altera data de preco
                    Int32 vaco = (Int32)Session["VACO"];
                    if (vm.VACO_CD_ID != vaco)
                    {
                        vm.PACI_DT_PRECO = DateTime.Today.Date;
                    }

                    // Executa a operação
                    Session["FlagAlteraPaciente"] = 1;
                    PACIENTE item = Mapper.Map<PacienteViewModel, PACIENTE>(vm);
                    item.PACI_DT_ACESSO = DateTime.Now;
                    item.PACI_IN_COMPLETADO = 1;
                    Int32 volta = baseApp.ValidateEdit(item, (PACIENTE)Session["PacienteAntes"], usuarioLogado);

                    // Verifica se não houve alteração
                    if (item == objetoAntes)
                    {
                        Session["FlagAlteraPaciente"] = 0;
                    }

                    // Trata mudanca de padrao de anamnese
                    PACIENTE paciente = baseApp.GetItemById(item.PACI__CD_ID);
                    if ((Int32)Session["PadraoAnamnese"] == 1)
                    {
                        if (item.PACI_IN_PADRAO_ANAMNESE != 1)
                        {
                            PACIENTE_ANAMNESE anamnese = paciente.PACIENTE_ANAMNESE.Where(p => p.PAAM_IN_ATIVO == 1).FirstOrDefault();
                            Int32 a = MontarAnamnese(anamnese.PAAM_CD_ID);
                        }
                    }

                    // Atualiza estado
                    listaMaster = new List<PACIENTE>();
                    Session["ListaPaciente"] = null;
                    Session["ListaPacienteBase"] = null;
                    Session["IncluirPaciente"] = 0;
                    Session["PacienteAlterada"] = 1;
                    Session["LinhaAlterada"] = item.PACI__CD_ID;
                    Session["FlagPaciente"] = 1;

                    // Grava historico
                    PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                    hist.ASSI_CD_ID = usuarioLogado.ASSI_CD_ID;
                    hist.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                    hist.PACI_CD_ID = item.PACI__CD_ID;
                    hist.PAHI_DT_DATA = DateTime.Now;
                    hist.PAHI_IN_TIPO = 1;
                    hist.PAHI_IN_CHAVE = item.PACI__CD_ID;
                    hist.PAHI_NM_OPERACAO = "Paciente - Edição";
                    hist.PAHI_DS_DESCRICAO = "Edição do paciente " + item.PACI_NM_NOME;
                    Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);

                    // Mensagem do CRUD
                    Session["MsgCRUD"] = "As informações do(a) paciente " + paciente.PACI_NM_NOME.ToUpper() + " foram alteradas com sucesso.";
                    Session["MensPaciente"] = 61;

                    // Trata retorno
                    if ((Int32)Session["IncluirConsultaArea"] == 2)
                    {
                        return RedirectToAction("MontarTelaAreaPacienteVer", "AreaPaciente");
                    }
                    if ((Int32)Session["VoltarProceder"] == 1)
                    {
                        return RedirectToAction("VoltarProcederConsulta");
                    }
                    if ((Int32)Session["VoltaAusencia"] == 1)
                    {
                        return RedirectToAction("MontarTelaAusencias", "Paciente2");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 20)
                    {
                        return RedirectToAction("VoltarProcederConsulta");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 2)
                    {
                        return RedirectToAction("MontarTelaSolicitacoes");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 3)
                    {
                        return RedirectToAction("MontarTelaAtestados");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 8)
                    {
                        return RedirectToAction("VerMedicamentosPacienteForm");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 9)
                    {
                        return RedirectToAction("MontarTelaEncerrarConsulta", "Financeiro");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 98)
                    {
                        return RedirectToAction("MontarTelaLocacao", "Locacao");
                    }
                    if (Session["FiltroPaciente"] != null)
                    {
                        FiltrarPaciente((PACIENTE)Session["FiltroPaciente"]);
                    }

                    if ((Int32)Session["VoltaPaciente"] == 2)
                    {
                        return RedirectToAction("VerCardsPaciente");
                    }

                    // Retorno normal
                    if ((Int32)Session["FlagAlteraPaciente"] == 1)
                    {
                        Session["MensPaciente"] = 66;
                    }
                    Session["TipoSolicitacao"] = 1;
                    return RedirectToAction("VoltarAnexoPaciente");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

        [HttpGet]
        public ActionResult VerPaciente(Int32 id)
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_ACESSO_PACIENTE == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente - Consulta";
                        return RedirectToAction("MontarTelaCentralPaciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];

                // Prepara listas
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;

                // Verifica possibilidade E-Mail
                List<MENSAGENS_ENVIADAS_SISTEMA> mens = CarregaMensagemEnviada();
                ViewBag.EMail = 1;
                Int32 num = mens.Where(p => p.MEEN_DT_DATA_ENVIO.Value.Month == DateTime.Today.Date.Month & p.MEEN_DT_DATA_ENVIO.Value.Year == DateTime.Today.Date.Year & p.MEEN_IN_TIPO == 1).ToList().Count;
                if ((Int32)Session["NumEMail"] <= num)
                {
                    ViewBag.EMail = 0;
                }

                // Verifica possibilidade SMS
                ViewBag.SMS = 1;
                num = mens.Where(p => p.MEEN_DT_DATA_ENVIO.Value.Month == DateTime.Today.Date.Month & p.MEEN_DT_DATA_ENVIO.Value.Year == DateTime.Today.Date.Year & p.MEEN_IN_TIPO == 2).ToList().Count;
                if ((Int32)Session["NumSMS"] <= num)
                {
                    ViewBag.SMS = 0;
                }

                // Carrega paciente
                PACIENTE item = baseApp.GetItemById(id);
                Session["Paciente"] = item;

                // Carrega Listas
                List<PACIENTE_PRESCRICAO> listaPrescricao = item.PACIENTE_PRESCRICAO.Where(p => p.PAPR_IN_ATIVO == 1).ToList();
                Session["ListaPrescricao"] = listaPrescricao;
                List<PACIENTE_ATESTADO> listaAtestado = item.PACIENTE_ATESTADO.Where(p => p.PAAT_IN_ATIVO == 1).ToList();
                Session["ListaAtestado"] = listaAtestado;
                List<PACIENTE_SOLICITACAO> listaSolicitacao = item.PACIENTE_SOLICITACAO.Where(p => p.PASO_IN_ATIVO == 1).ToList();
                Session["ListaSolicitacao"] = listaSolicitacao;
                List<PACIENTE_EXAMES> listaExame = item.PACIENTE_EXAMES.Where(p => p.PAEX_IN_ATIVO == 1).ToList();
                Session["ListaExame"] = listaExame;
                List<PACIENTE_CONSULTA> listaConsulta = item.PACIENTE_CONSULTA.Where(p => p.PACO_IN_ATIVO == 1).ToList();
                Session["ListaConsulta"] = listaConsulta;
                List<PACIENTE_PRESCRICAO_ITEM> listaRemedio = item.PACIENTE_PRESCRICAO_ITEM.Where(p => p.PAPI_IN_ATIVO == 1).ToList();
                Session["ListaRemedio"] = listaRemedio;

                // Trata mensagens
                if (Session["MensPaciente"] != null)
                {
                    // Mensagem
                    if ((Int32)Session["MensPaciente"] == 5)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0019", CultureInfo.CurrentCulture));
                    }
                }

                // Indicadores
                ViewBag.NivelPaciente = 1;

                // Carrega view
                Session["FlagMensagensEnviadas"] = 2;
                ViewBag.Incluir = 1;
                objetoAntes = item;
                Session["Paciente"] = item;
                Session["IdPaciente"] = id;
                Session["IdVolta"] = id;
                Session["VoltaCEP"] = 1;
                Session["VoltaMsg"] = 2;
                Session["NivelExame"] = 1;
                Session["MensPaciente"] = null;
                Session["PacienteAlterada"] = 1;
                Session["VoltaGrupo"] = 22;
                Session["VoltaAtestado"] = 2;
                Session["NivelExame"] = 1;
                Session["VoltaAnamnese"] = 1;
                Session["VoltaFisico"] = 1;
                Session["VoltarConsulta"] = 3;
                Session["ModoConsulta"] = 0;
                Session["EditarVer"] = 1;

                PacienteViewModel vm = Mapper.Map<PACIENTE, PacienteViewModel>(item);

                // Carrega ultima anamnese
                List<PACIENTE_ANAMNESE> anamneses = item.PACIENTE_ANAMNESE.Where(p => p.PAAM_DT_DATA.Date <= DateTime.Today.Date & p.PAAM_IN_ATIVO == 1).ToList();
                PACIENTE_ANAMNESE anamnese = null;
                Int32 temAnamnese = 0;
                if (anamneses.Count() > 0)
                {
                    temAnamnese = 1;
                    anamnese = anamneses.OrderByDescending(p => p.PAAM_DT_DATA).ToList().FirstOrDefault();
                    vm.PAAN_DS_MOTIVO_CONSULTA = anamnese.PAAM_DS_MOTIVO_CONSULTA;
                    vm.PAAN_DS_QUEIXA_PRINCIPAL = anamnese.PAAM_DS_QUEIXA_PRINCIPAL;
                    vm.PAAN_DS_HISTORIA_FAMILIAR = anamnese.PAAM_DS_HISTORIA_FAMILIAR;
                    vm.PAAN_DS_HISTORIA_DOENCA_ATUAL = anamnese.PAAM_DS_HISTORIA_DOENCA_ATUAL;
                    vm.PAAN_DS_DIAGNOSTICO_1 = anamnese.PAAM_DS_DIAGNOSTICO_1;
                    vm.PAAN_DS_CONDUTA = anamnese.PAAM_DS_CONDUTA;
                    vm.PAAN_DT_DATA = anamnese.PAAM_DT_DATA;
                    Session["IdUltimaAnamnese"] = anamnese.PAAM_CD_ID;

                }
                Session["TemAnamnese"] = temAnamnese;

                // Carrega ultimo exame físico
                List<PACIENTE_EXAME_FISICOS> fisicos = item.PACIENTE_EXAME_FISICOS.Where(p => p.PAEF_DT_DATA.Value.Date <= DateTime.Today.Date & p.PAEF_IN_ATIVO == 1).ToList();
                PACIENTE_EXAME_FISICOS fisico = null;
                Int32 temFisico = 0;
                if (fisicos.Count() > 0)
                {
                    temFisico = 1;
                    fisico = fisicos.OrderByDescending(p => p.PAEF_DT_DATA).ToList().FirstOrDefault();
                    vm.PAEF_DT_DATA = fisico.PAEF_DT_DATA;
                    vm.PAEF_NR_PA_ALTA = fisico.PAEF_NR_PA_ALTA;
                    vm.PAEF_NR_PA_BAIXA = fisico.PAEF_NR_PA_BAIXA;
                    vm.PAEF_NR_FREQUENCIA_CARDIACA = fisico.PAEF_NR_FREQUENCIA_CARDIACA;
                    vm.PAEF_NR_PESO = fisico.PAEF_NR_PESO;
                    vm.PAEF_NR_TEMPERATURA = fisico.PAEF_NR_TEMPERATURA;
                    vm.PAEF_NR_ALTURA = fisico.PAEF_NR_ALTURA;
                    vm.PAEF_VL_IMC = fisico.PAEF_VL_IMC;
                    vm.PAEF_DS_EXAME_FISICO = fisico.PAEF_DS_EXAME_FISICO;
                    Session["IdUltimoFisico"] = fisico.PAEF_CD_ID;
                }
                Session["TemFisico"] = temFisico;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_VER", "Paciente", "VerPaciente");

                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

