        [HttpPost]
        [ValidateAntiForgeryToken]
        [ValidateInput(false)]
        public ActionResult IncluirPrescricaoItem(PacientePrescricaoItemViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
            Int32 idAss = (Int32)Session["IdAssinante"];
            ViewBag.TipoForma = new SelectList(CarregaTipoForma(), "TIFO_CD_ID", "TIFO_NM_NOME");
            PACIENTE_PRESCRICAO prescricao = baseApp.GetPrescricaoById((Int32)Session["IdPrescricao"]);
            ViewBag.Medicamentos = new SelectList(CarregaMedicamentos().Where(p => p.TICO_CD_ID == prescricao.TICO_CD_ID).ToList().OrderBy(p => p.MEDI_NM_MEDICAMENTO).ToList(), "MEDI_CD_ID", "MEDI_DS_DESCRICAO");
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização
                    vm.PAPI_NM_REMEDIO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAPI_NM_REMEDIO);
                    vm.PAPI_DS_POSOLOGIA = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAPI_DS_POSOLOGIA);
                    vm.PAPI_NM_GENERICO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAPI_NM_GENERICO);
                    vm.PACIENTE_PRESCRICAO.PAPR_NM_REMEDIO = "-";
                    vm.PAPI_NM_LABORATORIO = (String)Session["Laboratorio"];
                    vm.PAPI_NR_QUANTIDADE = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAPI_NR_QUANTIDADE);

                    // Critica
                    if (vm.PACIENTE_PRESCRICAO.TICO_CD_ID == 2)
                    {
                        if (vm.PAPI_NR_QUANTIDADE == null)
                        {
                            vm.PAPI_NR_QUANTIDADE = "1 embalagem";
                        }
                    }

                    // Executa a operação
                    CONFIGURACAO conf = CarregaConfiguracaoGeral();
                    PACIENTE_PRESCRICAO_ITEM item = Mapper.Map<PacientePrescricaoItemViewModel, PACIENTE_PRESCRICAO_ITEM>(vm);
                    Int32 volta = baseApp.ValidateCreatePrescricaoItem(item);

                    // Verifica retorno
                    Session["IdPrescricao"] = item.PAPR_CD_ID;
                    Session["PacienteAlterada"] = 1;
                    Session["NivelPaciente"] = 8;
                    Session["ListaMedicamentos"] = null;

                    // Configura serilização
                    JsonSerializerSettings settings = new JsonSerializerSettings
                    {
                        ReferenceLoopHandling = ReferenceLoopHandling.Ignore,
                        NullValueHandling = NullValueHandling.Ignore
                    };

                    // Monta Log
                    DTO_Paciente_ItemPrescricao dto = MontarItemPrescricaoDTOObj(item);
                    String json = JsonConvert.SerializeObject(dto, settings);
                    LOG log = new LOG
                    {
                        LOG_DT_DATA = DateTime.Now,
                        ASSI_CD_ID = usuarioLogado.ASSI_CD_ID,
                        USUA_CD_ID = usuarioLogado.USUA_CD_ID,
                        LOG_NM_OPERACAO = "Paciente - Item de Prescrição - Inclusão",
                        LOG_IN_ATIVO = 1,
                        LOG_TX_REGISTRO = json,
                        LOG_IN_SISTEMA = 6
                    };
                    Int32 volta1 = logApp.ValidateCreate(log);

                    // Grava historico
                    PACIENTE pac = baseApp.GetItemById(item.PACI_CD_ID);
                    PACIENTE_PRESCRICAO pres = baseApp.GetPrescricaoById(item.PAPR_CD_ID);
                    Session["IdPrescricao"] = pres.PAPR_CD_ID;
                    String novo = item.PAPI_NM_REMEDIO;
                    String poso = item.PAPI_DS_POSOLOGIA;
                    String presc = ">>> Prescrição: " + pres.PAPR_GU_GUID + " <<<";

                    PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                    hist.ASSI_CD_ID = usuarioLogado.ASSI_CD_ID;
                    hist.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                    hist.PACI_CD_ID = item.PACI_CD_ID;
                    hist.PAHI_DT_DATA = DateTime.Now;
                    hist.PAHI_IN_TIPO = 4;
                    hist.PAHI_IN_CHAVE = item.PAPI_CD_ID;
                    hist.PAHI_NM_OPERACAO = "Paciente - Inclusão de Item de Prescrição";
                    hist.PAHI_DS_DESCRICAO = "Paciente: " + pac.PACI_NM_NOME + " - Prescrição: " + pres.PAPR_GU_GUID + " Item incluído: " + item.PAPI_NM_REMEDIO;
                    Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);

                    // Cadastra medicamento
                    if (conf.CONF_IN_INCLUIR_REMEDIO == 1)
                    {
                        MEDICAMENTO meds = CarregaMedicamentos().Where(p => p.MEDI_NM_MEDICAMENTO.ToUpper() == item.PAPI_NM_REMEDIO.ToUpper()).FirstOrDefault();
                        if (meds == null)
                        {
                            MEDICAMENTO med = new MEDICAMENTO();
                            med.ASSI_CD_ID = idAss;
                            med.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                            med.TIFO_CD_ID = item.TIFO_CD_ID;
                            med.TICO_CD_ID = pres.TICO_CD_ID;
                            med.MEDI_NM_MEDICAMENTO = item.PAPI_NM_REMEDIO;
                            med.MEDI_NM_GENERICO = item.PAPI_NM_GENERICO;
                            med.MEDI_NM_APRESENTACAO = item.PAPI_NM_APRESENTACAO;
                            med.MEDI_NM_LABORATORIO = item.PAPI_NM_LABORATORIO;
                            med.MEDI_IN_ATIVO = 1;
                            med.MEDI_DS_POSOLOGIA = item.PAPI_DS_POSOLOGIA;
                            Int32 voltaMed = medApp.ValidateCreate(med, usuarioLogado);
                        }
                    }

                    // Atualiza anamnese
                    PACIENTE paci = baseApp.GetItemById(item.PACI_CD_ID);
                    PACIENTE_ANAMNESE anaBase = paci.PACIENTE_ANAMNESE.FirstOrDefault();
                    PACIENTE_ANAMNESE ana = RemontarAnamnese(anaBase);

                    if (ana != null)
                    {
                        String velho = ana.PAAM_NM_MEDICAMENTO;
                        String dataHoje = DateTime.Today.Date.ToLongDateString();
                        dataHoje = "*** Revisão de Consulta em [" + dataHoje + "] ***";
                        if (velho == null & novo != String.Empty)
                        {
                            ana.PAAM_NM_MEDICAMENTO = dataHoje + "\r\n" + presc + "\r\n" + novo + "\r\n" + poso;
                        }
                        if (velho != null & novo != String.Empty)
                        {
                            String tripa = velho.Substring(velho.Length - 4, 4);
                            if (tripa == "\r\n")
                            {
                                velho = velho.Substring(0, velho.Length - 4);
                            }
                            ana.PAAM_NM_MEDICAMENTO = velho + "\r\n\r\n" + dataHoje + "\r\n" + presc + "\r\n" + novo + "\r\n" + poso;
                        }
                        Int32 voltaAna = baseApp.ValidateEditAnamnese(ana);

                        // Remonta anamnese completa
                        Int32 voltaM = MontarAnamnese(ana.PAAM_CD_ID);

                    }

                    // Retorno
                    if (pres.TICO_CD_ID == 2 || pres.TICO_CD_ID == 3)
                    {
                        return RedirectToAction("VoltarEditarPrescricao");
                    }
                    return RedirectToAction("IncluirPrescricaoItem");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

