                vm.PAAT_DT_ENVIO = null;
                vm.PAAT_IN_PDF = 0;
                vm.PAAT_NR_ENVIOS = 0;
                vm.PAAT_IN_DATA = 1;
                vm.PAAT_DT_EMISSAO_COMPLETA = DateTime.Now;
                vm.PAAT_TK_TOKEN = Cryptography.GenerateToken(6);
