                }
                else
                {
                    vm.PACI_CD_ID = 0;
                    vm.PACIENTE = null;
                    Session["TipoSolicitacao"] = 0;
                    ViewBag.NomePaciente = String.Empty;
                }
                vm.PASO_IN_ATIVO = 1;
                vm.PASO_DT_EMISSAO = DateTime.Now;
                vm.PASO_GU_GUID = Xid.NewXid().ToString();
                vm.USUA_CD_ID = usuario.USUA_CD_ID;
                vm.ASSI_CD_ID = idAss;
                vm.PASO_GU_GUID_ENVIO = null;
                vm.PASO_IN_ENVIADO = 0;
                vm.PASO_DT_ENVIO = null;
                vm.PASO_IN_PDF = 0;
                vm.PASO_NR_ENVIOS = 0;
                vm.PASO_IN_DATA = 1;
                vm.PASO_DT_EMISSAO_COMPLETA = DateTime.Now;
                vm.PASO_TK_TOKEN = Cryptography.GenerateToken(6);
                vm.PASO_IN_ASSINADO_DIGITAL = conf.CONF_IN_ASSINA_DIGITAL_SOLICITACAO;
                if ((Int32)Session["IdConsultaCria"] == 0)
                {
                    vm.PACO_CD_ID = null;
                }
                else
                {
                    vm.PACO_CD_ID = (Int32)Session["IdConsulta"];
                }
                if ((Int32)Session["ModoConsulta"] != 0)
                {
                    vm.PACO_CD_ID = (Int32)Session["IdConsulta"];
                    PACIENTE_CONSULTA consulta = baseApp.GetConsultaById((Int32)Session["IdConsulta"]);
                    vm.PACIENTE_CONSULTA = consulta;
                }
                else
                {
                    vm.PACO_CD_ID = null;
                }

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_SOLICITACAO_INCLUIR", "Paciente", "IncluirSolicitacao");

                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult IncluirSolicitacao(PacienteSolicitacaoViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
            Int32 idAss = (Int32)Session["IdAssinante"];
            ViewBag.ModeloSolicitacao = new SelectList(CarregaModeloSolicitacao().OrderBy(p => p.SOLI_NM_TITULO).ToList(), "SOLI_CD_ID", "SOLI_NM_TITULO");
            ViewBag.TipoExame = new SelectList(CarregaTipoExame(), "TIEX_CD_ID", "TIEX_NM_NOME");
            var trata = new List<SelectListItem>();
            trata.Add(new SelectListItem() { Text = "Sim", Value = "1" });
            trata.Add(new SelectListItem() { Text = "Não", Value = "0" });
            ViewBag.TrataData = new SelectList(trata, "Value", "Text");
            ViewBag.Paciente = new SelectList(CarregaPaciente(), "PACI__CD_ID", "PACI_NM_NOME");
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização
                    vm.PASO_NM_TITULO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PASO_NM_TITULO);
                    vm.PASO_TX_TEXTO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PASO_TX_TEXTO);
                    vm.PASO_DS_INDICACAO_CLINICA = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PASO_DS_INDICACAO_CLINICA);

                    // Critica
                    if (vm.PACI_CD_ID == 0 || vm.PACI_CD_ID == null)
                    {
                        Session["MensPaciente"] = 1;
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0527", CultureInfo.CurrentCulture));
                        return View(vm);
                    }
                    if (vm.PASO_IN_DATA == null)
                    {
                        vm.PASO_IN_DATA = 1;
                    }
                    if (vm.PASO_DT_EMISSAO.Value.Date < DateTime.Today.Date)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0720", CultureInfo.CurrentCulture));
                        return View(vm);
                    }

                    // Executa a operação
                    PACIENTE_SOLICITACAO item = Mapper.Map<PacienteSolicitacaoViewModel, PACIENTE_SOLICITACAO>(vm);
                    item.PASO_IN_ASSINADO_DIGITAL = 1;
                    Int32 volta = baseApp.ValidateCreateSolicitacao(item);

                    // Verifica retorno
                    Session["IdSolicitacao"] = item.PASO_CD_ID;
                    Session["PacienteAlterada"] = 1;
                    Session["NivelPaciente"] = 12;
                    Session["SolicitacoesAlterada"] = 1;
                    Session["ListaSolicitacoes"] = null;
                    Session["ListaSolicitacao"] = null;
                    Session["IdPaciente"] = item.PACI_CD_ID;
                    CONFIGURACAO conf = CarregaConfiguracaoGeral();

                    // Gerar e gravar QRCode
                    //String fileNameQR = "Solicitacao_QRCode_" + item.PASO_GU_GUID + ".png";
                    //String caminhoQR = "/Imagens/" + usuarioLogado.ASSI_CD_ID.ToString() + "/Pacientes/" + item.PACI_CD_ID.ToString() + "/QRCode/";
                    //String pathQR = Path.Combine(Server.MapPath(caminhoQR), fileNameQR);

                    //CONFIGURACAO conf = CarregaConfiguracaoGeral();
                    //PACIENTE_SOLICITACAO solicitacao = baseApp.GetSolicitacaoById(item.PASO_CD_ID);
                    //String linkBase = "https://webdoctorformbase.azurewebsites.net/api/ExibirFormulario";
                    //String sufixo = "?Token=" + solicitacao.PASO_TK_TOKEN;
                    //sufixo += "&ID=" + solicitacao.PASO_CD_ID.ToString();
                    //sufixo += "&Tipo=2";
                    //String url = linkBase + sufixo;
                    //QrCodeHelper.GenerateQrCodeAndSave(url, pathQR);
                    //solicitacao.PASO_AQ_ARQUIVO_QRCODE = "~" + caminhoQR + fileNameQR;
                    //Int32 voltaP = baseApp.ValidateEditSolicitacao(solicitacao);

                    // 1. Definição do nome e caminho virtual (Blob Name)
                    String fileNameQR = "Solicitacao_QRCode_" + item.PASO_GU_GUID + ".png";

                    // O Azure precisa do caminho sem a "/" inicial: "Imagens/..."
                    String caminhoLimpo = "Imagens/" + usuarioLogado.ASSI_CD_ID.ToString() + "/Pacientes/" + item.PACI_CD_ID.ToString() + "/QRCode/" + fileNameQR;

                    // 2. Montagem da URL do Atestado (Lógica original)
                    PACIENTE_SOLICITACAO atestado = baseApp.GetSolicitacaoById(item.PASO_CD_ID);
                    String linkBase = "https://webdoctorformbase.azurewebsites.net/api/ExibirFormulario";
                    String url = $"{linkBase}?Token={atestado.PASO_TK_TOKEN}&ID={atestado.PASO_CD_ID}&Tipo=1";

                    // 3. Gerar o QRCode em memória
                    byte[] qrCodeBytes = QrCodeHelper.GenerateQrCodeBytes(url);

                    // 4. Upload para o Azure Storage
                    string connectionString = conf.CONF_NM_STORAGE_CONN;
                    string containerName = conf.CONF_NM_STORAGE_CONTAINER;

                    BlobServiceClient blobServiceClient = new BlobServiceClient(connectionString);
                    BlobContainerClient containerClient = blobServiceClient.GetBlobContainerClient(containerName);
                    BlobClient blobClient = containerClient.GetBlobClient(caminhoLimpo);

                    using (var stream = new MemoryStream(qrCodeBytes))
                    {
                        var blobHttpHeader = new BlobHttpHeaders { ContentType = "image/png" };
                        blobClient.Upload(stream, blobHttpHeader);
                    }

                    // 5. Grava no banco exatamente no padrão solicitado: ~Imagens/...
                    // Note que não há "/" entre o "~" e o "Imagens"
                    atestado.PASO_AQ_ARQUIVO_QRCODE = "~" + caminhoLimpo;

                    Int32 voltaP = baseApp.ValidateEditSolicitacao(atestado);

                    // Configura serilização
                    JsonSerializerSettings settings = new JsonSerializerSettings
                    {
                        ReferenceLoopHandling = ReferenceLoopHandling.Ignore,
                        NullValueHandling = NullValueHandling.Ignore
                    };

                    // Monta Log
                    DTO_Paciente_Solicitacao dto = MontarPacienteSolicitacaoDTOObj(item);
                    String json = JsonConvert.SerializeObject(dto, settings);
                    LOG log = new LOG
                    {
                        LOG_DT_DATA = DateTime.Now,
                        ASSI_CD_ID = usuarioLogado.ASSI_CD_ID,
                        USUA_CD_ID = usuarioLogado.USUA_CD_ID,
                        LOG_NM_OPERACAO = "Paciente - Solicitação - Criação",
                        LOG_IN_ATIVO = 1,
                        LOG_TX_REGISTRO = json,
                        LOG_IN_SISTEMA = 6
                    };
                    Int32 volta1 = logApp.ValidateCreate(log);

                    // Grava historico
                    PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                    PACIENTE pac = baseApp.GetItemById(item.PACI_CD_ID.Value);
                    hist.ASSI_CD_ID = usuarioLogado.ASSI_CD_ID;
                    hist.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                    hist.PACI_CD_ID = item.PACI_CD_ID;
                    hist.PAHI_DT_DATA = DateTime.Now;
                    hist.PAHI_IN_TIPO = 6;
                    hist.PAHI_IN_CHAVE = item.PASO_CD_ID;
                    hist.PAHI_NM_OPERACAO = "Paciente - Criação de Solicitação";
                    hist.PAHI_DS_DESCRICAO = "Paciente " + pac.PACI_NM_NOME + " - Solicitação criada" + item.PASO_GU_GUID;
                    Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);

                    // Cadastra modelo de solicitação
                    if (conf.CONF_IN_INCLUIR_SOLICITACAO == 1)
                    {
                        SOLICITACAO sol = new SOLICITACAO();
                        sol.ASSI_CD_ID = idAss;
                        sol.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                        sol.TIEX_CD_ID = item.TIEX_CD_ID.Value;
                        sol.SOLI_NM_TITULO = item.PASO_NM_TITULO;
                        sol.SOLI_NM_INDICACAO = item.PASO_DS_INDICACAO_CLINICA;
                        sol.SOLI_DS_DESCRICAO = item.PASO_TX_TEXTO;
                        sol.SOLI_IN_ATIVO = 1;
                        Int32 voltaSol = solApp.ValidateCreate(sol, usuarioLogado);
                    }

                    // Atualiza prontuário
                    if (conf.CONF_IN_DOC_PRONTUARIO == 1)
                    {
                        PACIENTE_ANAMNESE ana = pac.PACIENTE_ANAMNESE.Where(p => p.PAAM_IN_ATIVO == 1).FirstOrDefault();
                        PACIENTE_ANAMNESE anan = RemontarAnamnese(ana);
                        String velho = anan.PAAM_TX_TEXTO_LIVRE;
                        String novo = "Emissão de Solicitação de Exame - " + atestado.PASO_NM_TITULO.ToUpper() + "\r\n" + atestado.PASO_TX_TEXTO;
                        String dataHoje = DateTime.Today.Date.ToLongDateString();
                        dataHoje = "*** Consulta em [" + dataHoje + "] ***";
                        if (anan.PAAM_TX_TEXTO_LIVRE != null)
                        {
                            String anot = dataHoje + "\r\n" + novo;
                            if (velho == null & novo != String.Empty)
                            {
                                anan.PAAM_TX_TEXTO_LIVRE = dataHoje + "\r\n" + novo;
                            }
                            if (velho != null & novo != String.Empty)
                            {
                                String tripa = velho.Substring(velho.Length - 4, 4);
                                if (tripa == "\r\n")
                                {
                                    velho = velho.Substring(0, velho.Length - 4);
                                }
                                anan.PAAM_TX_TEXTO_LIVRE = velho + "\r\n\r\n" + dataHoje + "\r\n" + novo;
                            }
                        }
                        else
                        {
                            velho = anan.PAAM_TX_TEXTO_LIVRE;
                            anan.PAAM_TX_TEXTO_LIVRE = velho;
                        }

                        // Executa a operação
                        anan.PAAM_IN_ALTERADA = 1;
                        anan.PACO_CD_ID = vm.PACO_CD_ID;
                        Int32 voltaW = baseApp.ValidateEditAnamnese(anan);
                    }

                    // Mensagem do CRUD
                    Session["MsgCRUD"] = "A solicitação de exame " + item.PASO_GU_GUID + " do(a) paciente " + pac.PACI_NM_NOME.ToUpper() + " foi criada com sucesso.";
                    Session["MensPaciente"] = 61;

                    // Retorno
                    if ((Int32)Session["ModoConsulta"] == 1)
                    {
                        return RedirectToAction("VerListaSolicitacaoConsulta");
                    }
                    if ((Int32)Session["ModoConsulta"] == 2)
                    {
                        return RedirectToAction("VerListaSolicitacaoConsulta");
                    }
                    if ((Int32)Session["TipoSolicitacao"] == 1)
                    {
                        if ((Int32)Session["VoltaAtestado"] == 1)
                        {
                            return RedirectToAction("MontarTelaCentralPaciente");
                        }
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                    return RedirectToAction("MontarTelaSolicitacoes");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

