                    {
                        // Recupera consulta
                        PACIENTE_CONSULTA consulta = baseApp.GetConsultaById(item.PACO_CD_ID.Value);
                        Session["IdConsulta"] = consulta.PACO_CD_ID;

                        // Recupera exame fisico da consulta
