        [HttpGet]
        public ActionResult EnviarPrescricaoEMail(Int32 id)
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_PRESCRICAO_ENVIAR == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente - Prescrição - Envio";
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Prescricoes - Envio";

                // Recupera paciente e prescricao
                PACIENTE_PRESCRICAO prescricao = baseApp.GetPrescricaoById(id);
                PACIENTE paciente = baseApp.GetItemById(prescricao.PACI_CD_ID);
                Session["Paciente"] = paciente;
                ViewBag.Paciente = paciente;
                Session["Prescricao"] = prescricao;
                ViewBag.Prescricao = prescricao;
                Session["NivelPaciente"] = 8;
                Session["IdPrescricao"] = id;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/7/Ajuda7_5.pdf";
                ViewBag.NomePaciente = paciente.PACI_NM_NOME;
                String texto = "Segue em anexo a prescrição solicitada." + "\r\n" + "Atenciosamente.";

                MensagemViewModel mens = new MensagemViewModel();
                mens.NOME = paciente.PACI_NM_NOME;
                mens.ID = id;
                mens.MODELO = paciente.PACI_NM_EMAIL;
                mens.MENS_DT_CRIACAO = DateTime.Today.Date;
                mens.MENS_IN_TIPO = 1;
                mens.MENS_NM_CAMPANHA = paciente.PACI_NM_EMAIL;
                mens.MENS_NM_NOME = "Envio de Prescrição para Paciente: " + paciente.PACI_NM_NOME.ToUpper();
                mens.MENS_GU_GUID = prescricao.PAPR_GU_GUID;
                mens.MENS_DT_AGENDAMENTO = prescricao.PAPR_DT_DATA;
                mens.MENS_DT_ENVIO = prescricao.PAPR_DT_ENVIO;
                mens.MENS_NM_CABECALHO = paciente.PACI_NR_CPF;
                mens.MENS_NR_REPETICOES = prescricao.PAPR_NR_ENVIOS;
                mens.MENS_NM_ASSINATURA = usuario.USUA_NM_NOME;
                mens.CELULAR = paciente.PACI_NR_CELULAR;
                mens.TELEFONE = paciente.PACI_NR_TELEFONE;
                mens.MENS_IN_TIPO_EMAIL = 1;
                mens.TIPO_ENVIO = 1;
                mens.MENS_TX_TEXTO = texto;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_PRESCRICAO_EMAIL", "Paciente", "EnviarPrescricaoEMail");
                return View(mens);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }


        [HttpPost]
        public async Task<ActionResult> EnviarPrescricaoEMail(MensagemViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização
                    vm.MENS_TX_TEXTO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.MENS_TX_TEXTO);

                    // Executa a operação
                    PACIENTE_PRESCRICAO prescricao = (PACIENTE_PRESCRICAO)Session["Prescricao"];
                    USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
                    if (prescricao.TICO_CD_ID == 1)
                    {
                        if (prescricao.PAPR_IN_ASSINADO_DIGITAL == 0)
                        {
                            Int32 rel = GerarPrescricaoPDF_ComumNovaTeste();
                        }
                        else
                        {
                            Int32 rel = GerarPrescricaoPDF_ComumNovaTesteAssina();

                        }
                    }
                    else
                    {
                        if (prescricao.PAPR_IN_ASSINADO_DIGITAL == 0)
                        {
                            Int32 rel = GerarPrescricaoPDF_EspecialNovaTeste();
                        }
                        else
                        {

                        }
                        {
                            Int32 rel = GerarPrescricaoPDF_EspecialNovaTesteAssina();

                        }
                    }
                    Int32 volta = await ProcessaEnvioEMailPrescricao(vm, usuarioLogado);
                    USUARIO cont = (USUARIO)Session["Usuario"];
                    Session["NivelPaciente"] = 8;

                    // Atualiza prescricao
                    String idEnvio = Xid.NewXid().ToString();
                    PACIENTE_PRESCRICAO solicitacao = baseApp.GetPrescricaoById((Int32)Session["IdPrescricao"]);
                    solicitacao.PAPR_DT_ENVIO = DateTime.Today.Date;
                    solicitacao.PAPR_NR_ENVIOS = solicitacao.PAPR_NR_ENVIOS + 1;
                    solicitacao.PAPR_IN_ENVIADO = 1;
                    solicitacao.PAPR_GU_GUID_ENVIO = idEnvio;
                    Int32 volta1 = baseApp.ValidateEditPrescricao(solicitacao);
                    Session["ListaPrescricoes"] = null;

                    // Grava historico
                    PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                    PACIENTE pac = baseApp.GetItemById(solicitacao.PACI_CD_ID);
                    hist.ASSI_CD_ID = usuarioLogado.ASSI_CD_ID;
                    hist.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                    hist.PACI_CD_ID = solicitacao.PACI_CD_ID;
                    hist.PAHI_DT_DATA = DateTime.Now;
                    hist.PAHI_IN_TIPO = 6;
                    hist.PAHI_IN_CHAVE = solicitacao.PAPR_CD_ID;
                    hist.PAHI_NM_OPERACAO = "Paciente - Prescrição - Envio por E-Mail";
                    hist.PAHI_DS_DESCRICAO = "Paciente: " + pac.PACI_NM_NOME + " - Prescrição enviada: " + solicitacao.PAPR_GU_GUID;
                    Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);
                    Session["ListaPrescricoes"] = null;
                    Session["PrescricoesAlterada"] = 1;

                    // Envia aviso SMS
                    MensagemViewModel mens = new MensagemViewModel();
                    mens.NOME = pac.PACI_NM_NOME;
                    mens.ID = pac.PACI__CD_ID;
                    mens.MODELO = pac.PACI_NR_CELULAR;
                    mens.MENS_DT_CRIACAO = DateTime.Today.Date;
                    mens.MENS_IN_TIPO = 2;
                    mens.MENS_NM_NOME = "Aviso de Envio de Prescrição: " + pac.PACI_NM_NOME;
                    mens.PACI_CD_ID = pac.PACI__CD_ID;
                    Int32 voltaSMS = ProcessaEnvioSMSDocumento(mens, usuarioLogado, 3, solicitacao.PAPR_GU_GUID, solicitacao.PAPR_DT_EMISSAO_COMPLETA.Value);

                    // Mensagem do CRUD
                    Session["MsgCRUD"] = "A Prescrição " + solicitacao.PAPR_GU_GUID + " do(a) paciente " + pac.PACI_NM_NOME.ToUpper() + " foi enviada por e-mail com sucesso.";
                    Session["MensPaciente"] = 61;

                    // Retorno
                    if ((Int32)Session["VoltaMail"] == 1)
                    {
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                    else if ((Int32)Session["VoltaMail"] == 2)
                    {
                        return RedirectToAction("MontarTelaPrescricoes");
                    }
                    else if ((Int32)Session["VoltaMail"] == 3)
                    {
                        return RedirectToAction("VerListaPrescricaoConsulta");
                    }
                    else if ((Int32)Session["VoltaMail"] == 4)
                    {
                        return RedirectToAction("VerListaPrescricaoConsulta");
                    }
                    else if ((Int32)Session["VoltaMail"] == 5)
                    {
                        return RedirectToAction("MontarTelaCentralPaciente");
                    }
                    return RedirectToAction("MontarTelaPrescricoes");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

        [ValidateInput(false)]
        public async Task<Int32> ProcessaEnvioEMailPrescricao(MensagemViewModel vm, USUARIO usuario)
        {
            // Recupera dados
            Int32 idAss = (Int32)Session["IdAssinante"];
            USUARIO cont = (USUARIO)Session["Usuario"];
            String erro = null;
            String status = "Succeeded";
            String iD = Xid.NewXid().ToString();

            PACIENTE_PRESCRICAO prescricao = (PACIENTE_PRESCRICAO)Session["Prescricao"];
            PACIENTE paciente = baseApp.GetItemById(prescricao.PACI_CD_ID);

            // Configuração
            CONFIGURACAO conf = CarregaConfiguracaoGeral();

            // Prepara cabeçalho
            String cab = "Prezado Sr(a). <b>" + paciente.PACI_NM_NOME + "</b>";

            // Prepara rodape
            String classe = String.Empty;
            if (usuario.TIPO_CARTEIRA_CLASSE != null)
            {
                classe = cont.TIPO_CARTEIRA_CLASSE.TICL_NM_NOME + ": " + cont.USUA_NR_CLASSE;
            }
            String rod = "<b>" + cont.USUA_NM_NOME + "</b><br />";
            if (usuario.ESPECIALIDADE != null)
            {
                rod += usuario.ESPECIALIDADE.ESPE_NM_NOME + "<br />";
            }
            else
            {
                rod += usuario.USUA_NM_ESPECIALIDADE + "<br />";
            }
            rod += classe + "  CPF: " + cont.USUA_NR_CPF;

            // Prepara corpo do e-mail e trata link
            String corpo = vm.MENS_TX_TEXTO;
            StringBuilder str = new StringBuilder();
            str.AppendLine(corpo);
            String body = str.ToString();
            body = body.Replace("\r\n", "<br />");
            String emailBody = cab + "<br /><br />" + body + "<br /><br />" + rod;

            // Incluir PDF como anexo
            List<AttachmentModel> models = new List<AttachmentModel>();
            //String caminho = "/Imagens/" + idAss.ToString() + "/Pacientes/" + paciente.PACI__CD_ID.ToString() + "/Atestado/";
            String caminho = "/Temp/";
            String fileNamePDF = "Prescricao_" + paciente.PACI_NM_NOME + "_" + prescricao.PAPR_GU_GUID + ".pdf";
            String path = Path.Combine(Server.MapPath(caminho), fileNamePDF);

            AttachmentModel model = new AttachmentModel();
            model.PATH = path;
            model.ATTACHMENT_NAME = fileNamePDF;
            model.CONTENT_TYPE = MediaTypeNames.Application.Pdf;
            models.Add(model);

            // Decriptografa chaves
            String emissor = CrossCutting.Cryptography.Decrypt(conf.CONF_NM_EMISSOR_AZURE_CRIP);
            String conn = CrossCutting.Cryptography.Decrypt(conf.CONF_CS_CONNECTION_STRING_AZURE_CRIP);

            // Monta e-mail
            NetworkCredential net = new NetworkCredential(conf.CONF_NM_SENDGRID_LOGIN, conf.CONF_NM_SENDGRID_PWD);
            EmailAzure mensagem = new EmailAzure();
            mensagem.ASSUNTO = "Paciente - " + paciente.PACI_NM_NOME.ToUpper() + " - Prescrição";
            mensagem.CORPO = emailBody;
            mensagem.DEFAULT_CREDENTIALS = false;
            mensagem.EMAIL_TO_DESTINO = paciente.PACI_NM_EMAIL;
            mensagem.NOME_EMISSOR_AZURE = emissor;
            mensagem.ENABLE_SSL = true;
            mensagem.NOME_EMISSOR = usuario.USUA_NM_NOME;
            mensagem.PORTA = conf.CONF_NM_PORTA_SMTP;
            mensagem.PRIORIDADE = System.Net.Mail.MailPriority.High;
            mensagem.SENHA_EMISSOR = conf.CONF_NM_SENDGRID_PWD;
            mensagem.SMTP = conf.CONF_NM_HOST_SMTP;
            mensagem.IS_HTML = true;
            mensagem.NETWORK_CREDENTIAL = net;
            mensagem.ConnectionString = conn;

            // Envia mensagem
            try
            {
                await CrossCutting.CommunicationAzurePackage.SendMailAsync(mensagem, models);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return 0;
            }

            // Grava envio
            if (status == "Succeeded")
            {
                vm.MENS_NM_NOME = "Paciente: " + paciente.PACI_NM_NOME.ToUpper() + " - Prescrição";
                vm.MENS_NM_CAMPANHA = paciente.PACI_NM_EMAIL;
                vm.FORN_CD_ID = null;
                vm.CLIE_CD_ID = null;
                vm.PACI_CD_ID = paciente.PACI__CD_ID;
                vm.MENS_IN_USUARIO = cont.USUA_CD_ID;
                EnvioEMailGeralBase envio = new EnvioEMailGeralBase(usuApp, confApp, meApp);
                Int32 voltaX = envio.GravarMensagemEnviada(vm, usuario, emailBody, status, iD, erro, "Paciente - Envio Prescrição");
                Session["MensPaciente"] = 999;
                Session["IdMail"] = iD;
            }
            else
            {
                Session["MensPaciente"] = 998;
                Session["IdMail"] = iD;
                Session["StatusMail"] = status;
            }

            // 4. APAGAR ARQUIVO LOCAL APÓS SUCESSO
            if (System.IO.File.Exists(path))
            {
                System.IO.File.Delete(path);
            }
            return 0;
        }


