                mens.MENS_GU_GUID = atestado.PAAT_GU_GUID;
                mens.MENS_DT_AGENDAMENTO = atestado.PAAT_DT_DATA;
                mens.MENS_DT_ENVIO = atestado.PAAT_DT_ENVIO;
