                mens.MENS_NR_REPETICOES = atestado.PAAT_NR_ENVIOS;
                mens.MENS_NM_ASSINATURA = usuario.USUA_NM_NOME;
                mens.MENS_NM_RODAPE = atestado.TIPO_ATESTADO.TIAT_NM_NOME;
