                cell.HorizontalAlignment = Element.ALIGN_LEFT;
                table.AddCell(cell);
                pdfDoc.Add(table);

                // Linha Horizontal
                line1 = new Paragraph("  ");
                pdfDoc.Add(line1);

                // Grid
                table = new PdfPTable(new float[] { 100f, 500f });
                table.WidthPercentage = 100;
                table.HorizontalAlignment = 0;
                table.SpacingBefore = 1f;
                table.SpacingAfter = 1f;

                cell = new PdfPCell(new Paragraph("Exame Solicitado: ", meuFont1Bold))
                {
                    VerticalAlignment = Element.ALIGN_MIDDLE,
                    HorizontalAlignment = Element.ALIGN_LEFT
                };
                cell.Colspan = 1;
                cell.Border = PdfPCell.NO_BORDER;
                cell.BackgroundColor = BaseColor.WHITE;
                table.AddCell(cell);
                cell = new PdfPCell(new Paragraph(solic.PASO_NM_TITULO, meuFont1))
                {
                    VerticalAlignment = Element.ALIGN_MIDDLE,
                    HorizontalAlignment = Element.ALIGN_LEFT
                };
                cell.Colspan = 1;
                cell.Border = PdfPCell.NO_BORDER;
                cell.BackgroundColor = BaseColor.WHITE;
                table.AddCell(cell);
                cell = new PdfPCell(new Paragraph("Indicação Clínica: ", meuFont1Bold))
                {
                    VerticalAlignment = Element.ALIGN_MIDDLE,
                    HorizontalAlignment = Element.ALIGN_LEFT
                };
                cell.Colspan = 1;
                cell.BackgroundColor = BaseColor.WHITE;
                cell.Border = PdfPCell.NO_BORDER;
                table.AddCell(cell);
                cell = new PdfPCell(new Paragraph(solic.PASO_DS_INDICACAO_CLINICA, meuFont1))
                {
                    VerticalAlignment = Element.ALIGN_MIDDLE,
                    HorizontalAlignment = Element.ALIGN_LEFT
                };
                cell.Colspan = 1;
                cell.Border = PdfPCell.NO_BORDER;
                cell.BackgroundColor = BaseColor.WHITE;
                table.AddCell(cell);
                pdfDoc.Add(table);

                // Texto da solicitacao
                line1 = new Paragraph("  ");
                pdfDoc.Add(line1);

                Chunk chunk3 = new Chunk("Especificação do Exame ou Recomendações/Observações:", FontFactory.GetFont("Arial", 10, Font.NORMAL, BaseColor.BLACK));
                Paragraph paragraph = new Paragraph(chunk3);
                paragraph.Alignment = Element.ALIGN_LEFT;
                pdfDoc.Add(paragraph);
                line1 = new Paragraph("  ");
                pdfDoc.Add(line1);

                Chunk chunk1 = new Chunk(solic.PASO_TX_TEXTO, FontFactory.GetFont("Arial", 9, Font.NORMAL, BaseColor.BLACK));
                pdfDoc.Add(chunk1);

                if (solic.PASO_IN_ASSINADO_DIGITAL == 0)
                {
                    // Ajusta espaço
                    line1 = new Paragraph("  ");
                    pdfDoc.Add(line1);
                    line1 = new Paragraph("  ");
                    pdfDoc.Add(line1);
                    line1 = new Paragraph("  ");
                    pdfDoc.Add(line1);
                    line1 = new Paragraph("  ");
                    pdfDoc.Add(line1);

                    //Assinatura manual
                    String assinatura = usuario.USUA_NM_PREFIXO + " " + usuario.USUA_NM_NOME + (usuario.USUA_NM_SUFIXO != null ? " " + usuario.USUA_NM_SUFIXO : "");
                    Chunk chunk4 = new Chunk(assinatura, FontFactory.GetFont("Arial", 12, Font.NORMAL, BaseColor.BLACK));
                    Paragraph paragraph1 = new Paragraph(chunk4);
                    paragraph1.Alignment = Element.ALIGN_CENTER;
                    pdfDoc.Add(paragraph1);
                }

                // Finaliza
                pdfWriter.CloseStream = false;
                pdfDoc.Close();

                // --- FINALIZAÇÃO DO DOCUMENTO BASE ---
                byte[] pdfOriginalBytes = msInput.ToArray();
                msInput.Dispose(); // Libera o stream original para garantir que não há travas

                if (pdfOriginalBytes == null || pdfOriginalBytes.Length == 0)
                    throw new Exception("Erro: PDF base não foi extraído corretamente.");

                byte[] pdfFinal = null;
                if (solic.PASO_IN_ASSINADO_DIGITAL == 1) // Se for para assinar com PFX
                {
                    if (certificado == 1)
                    {
                        // Monta o caminho relativo: ~/Certificados/ID/NomeArquivo.pfx
                        string caminhoRelativo = "~/Certificados/" + idAss.ToString() + "/" + conf.CONF_NM_LOCAL_CERTIFICADO;
                        PACIENTE paciente1 = baseApp.GetItemById(id.Value);

                        // Converte para o caminho físico real do servidor
                        string caminhoPFX = Server.MapPath(caminhoRelativo);
                        string senhaPFX = conf.CONF_NM_SENHA_CERTIFICADO;

                        using (MemoryStream msOutput = new MemoryStream())
                        {
                            if (!System.IO.File.Exists(caminhoPFX))
                            {
                                throw new Exception("Arquivo de certificado não encontrado em: " + caminhoPFX);
                            }

                            // 1. Carrega o certificado com flags de persistência para o Azure
                            X509Certificate2 cert = new X509Certificate2(caminhoPFX, senhaPFX,
                                X509KeyStorageFlags.Exportable |
                                X509KeyStorageFlags.MachineKeySet |
                                X509KeyStorageFlags.PersistKeySet);

                            // 2. Prepara componentes do BouncyCastle
                            Org.BouncyCastle.X509.X509Certificate bcCert = Org.BouncyCastle.Security.DotNetUtilities.FromX509Certificate(cert);
                            Org.BouncyCastle.Crypto.AsymmetricKeyParameter key = Org.BouncyCastle.Security.DotNetUtilities.GetKeyPair(cert.PrivateKey).Private;
                            Org.BouncyCastle.X509.X509Certificate[] chain = new Org.BouncyCastle.X509.X509Certificate[] { bcCert };

                            // 3. Cria o Reader e o Stamper
                            // IMPORTANTE: Usamos pdfOriginalBytes para garantir que os dados estão lá após o dispose do msInput
                            using (PdfReader reader = new PdfReader(pdfOriginalBytes))
                            {
                                // O '\0' indica que não estamos criando uma nova revisão, mas assinando
                                PdfStamper stamper = PdfStamper.CreateSignature(reader, msOutput, '\0');

                                PdfSignatureAppearance appearance = stamper.SignatureAppearance;
                                appearance.Reason = "Assinatura de Solicitação de Exame";
                                appearance.Location = paciente1.PACI_NM_CIDADE + ", " + (paciente1.UF != null ? paciente1.UF.UF_SG_SIGLA : "");

                                // Posição da assinatura
                                float xPos = 60;
                                float yPos = 160;
                                Rectangle posicaoAssinatura = new Rectangle(xPos, yPos, xPos + 300, yPos + 60);

                                // Se quiser que a assinatura apareça visualmente, descomente:
                                // appearance.SetVisibleSignature(posicaoAssinatura, reader.NumberOfPages, "Signature");

                                // 4. Realiza a assinatura
                                IExternalSignature es = new PrivateKeySignature(key, "SHA-256");
                                MakeSignature.SignDetached(appearance, es, chain, null, null, null, 0, CryptoStandard.CMS);

                                // --- AJUSTE CRÍTICO: FECHAR O STAMPER ANTES DE PEGAR O TOARRAY ---
                                stamper.Close();
                            }

                            pdfFinal = msOutput.ToArray();
                        }
                    }
                    else
                    {
                        pdfFinal = pdfOriginalBytes;
                    }
                }
                else
                {
                    pdfFinal = pdfOriginalBytes;
                }

                // 2. Envia o arquivo final (assinado ou não) para o navegador
                Response.Clear();
                Response.ContentType = "application/pdf";
                Response.AddHeader("content-disposition", "attachment;filename=" + nomeRel);
                Response.AddHeader("Content-Length", pdfFinal.Length.ToString());
                Response.BinaryWrite(pdfFinal);
                Response.Flush();
                Response.End();
                return 0;
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return 1;
            }
        }

        [ValidateInput(false)]
        public async Task<Int32> ProcessaEnvioEMailSolicitacao(MensagemViewModel vm, USUARIO usuario)
        {
            // Recupera dados
            Int32 idAss = (Int32)Session["IdAssinante"];
            USUARIO cont = (USUARIO)Session["Usuario"];
            String erro = null;
            String status = "Succeeded";
            String iD = Xid.NewXid().ToString();

            PACIENTE_SOLICITACAO solicitacao = (PACIENTE_SOLICITACAO)Session["Solicitacao"];
            PACIENTE paciente = baseApp.GetItemById(solicitacao.PACI_CD_ID.Value);

            // Configuração
            CONFIGURACAO conf = CarregaConfiguracaoGeral();

            // Prepara cabeçalho
            String cab = "Prezado Sr(a). <b>" + paciente.PACI_NM_NOME + "</b>";

            // Prepara rodape
            String classe = String.Empty;
            if (usuario.TIPO_CARTEIRA_CLASSE != null)
            {
                classe = cont.TIPO_CARTEIRA_CLASSE.TICL_NM_NOME + ": " + cont.USUA_NR_CLASSE;
            }
            String rod = "<b>" + cont.USUA_NM_NOME + "</b><br />";
            if (usuario.ESPECIALIDADE != null)
            {
                rod += usuario.ESPECIALIDADE.ESPE_NM_NOME + "<br />";
            }
            else
            {
                rod += usuario.USUA_NM_ESPECIALIDADE + "<br />";
            }
            rod += classe + "  CPF: " + cont.USUA_NR_CPF;

            // Prepara corpo do e-mail e trata link
            String corpo = vm.MENS_TX_TEXTO;
            StringBuilder str = new StringBuilder();
            str.AppendLine(corpo);
            String body = str.ToString();
            body = body.Replace("\r\n", "<br />");
            String emailBody = cab + "<br /><br />" + body + "<br /><br />" + rod;

            // Incluir PDF como anexo
            List<AttachmentModel> models = new List<AttachmentModel>();
            //String caminho = "/Imagens/" + idAss.ToString() + "/Pacientes/" + paciente.PACI__CD_ID.ToString() + "/Atestado/";
            String caminho = "/Temp/";
            String fileNamePDF = "Solicitacao_" + paciente.PACI_NM_NOME + "_" + solicitacao.PASO_GU_GUID + ".pdf";
            String path = Path.Combine(Server.MapPath(caminho), fileNamePDF);

            AttachmentModel model = new AttachmentModel();
            model.PATH = path;
            model.ATTACHMENT_NAME = fileNamePDF;
            model.CONTENT_TYPE = MediaTypeNames.Application.Pdf;
            models.Add(model);

            // Decriptografa chaves
            String emissor = CrossCutting.Cryptography.Decrypt(conf.CONF_NM_EMISSOR_AZURE_CRIP);
            String conn = CrossCutting.Cryptography.Decrypt(conf.CONF_CS_CONNECTION_STRING_AZURE_CRIP);

            // Monta e-mail
            NetworkCredential net = new NetworkCredential(conf.CONF_NM_SENDGRID_LOGIN, conf.CONF_NM_SENDGRID_PWD);
            EmailAzure mensagem = new EmailAzure();
            mensagem.ASSUNTO = "Paciente - " + paciente.PACI_NM_NOME + " - Solicitação de Exame";
            mensagem.CORPO = emailBody;
            mensagem.DEFAULT_CREDENTIALS = false;
            mensagem.EMAIL_TO_DESTINO = paciente.PACI_NM_EMAIL;
            mensagem.NOME_EMISSOR_AZURE = emissor;
            mensagem.ENABLE_SSL = true;
            mensagem.NOME_EMISSOR = usuario.USUA_NM_NOME;
            mensagem.PORTA = conf.CONF_NM_PORTA_SMTP;
            mensagem.PRIORIDADE = System.Net.Mail.MailPriority.High;
            mensagem.SENHA_EMISSOR = conf.CONF_NM_SENDGRID_PWD;
            mensagem.SMTP = conf.CONF_NM_HOST_SMTP;
            mensagem.IS_HTML = true;
            mensagem.NETWORK_CREDENTIAL = net;
            mensagem.ConnectionString = conn;

            // Envia mensagem
            try
            {
                await CrossCutting.CommunicationAzurePackage.SendMailAsync(mensagem, models);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return 0;
            }

            // Grava envio
            if (status == "Succeeded")
            {
                vm.MENS_NM_NOME = "Paciente - " + paciente.PACI_NM_NOME + " - Solicitação de Exame";
                vm.MENS_NM_CAMPANHA = paciente.PACI_NM_EMAIL;
                vm.FORN_CD_ID = null;
                vm.CLIE_CD_ID = null;
                vm.PACI_CD_ID = paciente.PACI__CD_ID;
                vm.MENS_IN_USUARIO = cont.USUA_CD_ID;
                EnvioEMailGeralBase envio = new EnvioEMailGeralBase(usuApp, confApp, meApp);
                Int32 voltaX = envio.GravarMensagemEnviada(vm, usuario, emailBody, status, iD, erro, "Paciente - Envio Solicitação");
                Session["MensPaciente"] = 992;
                Session["IdMail"] = iD;
            }
            else
            {
                Session["MensPaciente"] = 993;
                Session["IdMail"] = iD;
                Session["StatusMail"] = status;
            }

            // 4. APAGAR ARQUIVO LOCAL APÓS SUCESSO
            if (System.IO.File.Exists(path))
            {
                System.IO.File.Delete(path);
            }

            return 0;
        }

