        [HttpGet]
        public ActionResult EditarExameFisico(Int32 id)
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_ATESTADO_ALTERAR == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente - Exame Físico - Edição";
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];

                // Prepara view
                Session["NivelPaciente"] = 6;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/3/Ajuda3_8.pdf";
                Session["VoltaAnotacaoAnamnese"] = 4;

                PACIENTE pac = baseApp.GetItemById((Int32)Session["IdPaciente"]);
                PACIENTE_CONSULTA paco = pac.PACIENTE_CONSULTA.FirstOrDefault();
                PACIENTE_EXAME_FISICOS item = pac.PACIENTE_EXAME_FISICOS.Where(p => p.PAEF_IN_ATIVO == 1).FirstOrDefault();
                Session["IdUltimoFisico"] = item.PAEF_CD_ID;

                objetoAntes = pac;
                Int32? age = 0;
                if (pac.PACI_DT_NASCIMENTO != null)
                {
                    age = DateTime.Now.Subtract(pac.PACI_DT_NASCIMENTO.Value).Days;
                    age = age / 365;
                }

                PacienteExameFisicoViewModel vm = Mapper.Map<PACIENTE_EXAME_FISICOS, PacienteExameFisicoViewModel>(item);
                Session["ExameFisico"] = item;
                if (vm.PACIENTE_CONSULTA != null)
                {
                    vm.PACO_DT_CONSULTA = vm.PACIENTE_CONSULTA.PACO_DT_CONSULTA;
                }
                vm.PAEF_TX_RESULTADOS_OLD = item.PAEF_TX_RESULTADOS;
                vm.PAEF_TX_RESULTADOS = String.Empty;
                vm.Idade = age;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_FISICO_EDITAR", "Paciente", "EditarExameFisico");
                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult EditarExameFisico(PacienteExameFisicoViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            Int32 idAss = (Int32)Session["IdAssinante"];
            USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização
                    vm.PAEF_DS_TABAGISMO_LONG = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_TABAGISMO_LONG);
                    vm.PAEF_DS_EXERCICIO_FISICO_LONG = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_EXERCICIO_FISICO_LONG);
                    vm.PAEF_DS_ALCOOLISMO_LONG = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_ALCOOLISMO_LONG);
                    vm.PAEF_DS_ANTICONCEPCIONAL = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_ANTICONCEPCIONAL);
                    vm.PAEF_DS_MARCAPASSO_LONG = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_MARCAPASSO_LONG);
                    vm.PAEF_TX_CIRURGIAS = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_TX_CIRURGIAS);
                    vm.PAEF_DS_ALERGICO_LONG = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_ALERGICO_LONG);
                    vm.PAEF_DS_ONCOLOGICO_LONG = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_ONCOLOGICO_LONG);
                    vm.PAEF_DS_EXAME_FISICO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(vm.PAEF_DS_EXAME_FISICO);

                    // Verficar marcações das checkboxes
                    if (vm.PAEF_DS_TABAGISMO_LONG != null)
                    {
                        vm.PAEF_IN_TABAGISMO = 1;
                    }
                    if (vm.PAEF_DS_EXERCICIO_FISICO_LONG != null)
                    {
                        vm.PAEF_IN_EXERCICIO_FISICO = 1;
                    }
                    if (vm.PAEF_DS_ALCOOLISMO_LONG != null)
                    {
                        vm.PAEF_IN_ALCOOLISMO = 1;
                    }
                    if (vm.PAEF_DS_ANTICONCEPCIONAL != null)
                    {
                        vm.PAEF_IN_ANTICONCEPCIONAL = 1;
                    }
                    if (vm.PAEF_DS_MARCAPASSO_LONG != null)
                    {
                        vm.PAEF_IN_MARCAPASSO = 1;
                    }
                    if (vm.PAEF_TX_CIRURGIAS != null)
                    {
                        vm.PAEF_IN_CIRURGIAS = 1;
                    }
                    if (vm.PAEF_DS_ALERGICO_LONG != null)
                    {
                        vm.PAEF_IN_ANTE_ALERGICO = 1;
                    }
                    if (vm.PAEF_DS_ONCOLOGICO_LONG != null)
                    {
                        vm.PAEF_IN_ANTE_ONCOLOGICO = 1;
                    }

                    // Recalcula IMC
                    Double? imc = 0;
                    if (vm.PAEF_NR_ALTURA > 0 & vm.PAEF_NR_PESO > 0)
                    {
                        imc = Convert.ToDouble(vm.PAEF_NR_PESO) / Math.Pow((Convert.ToDouble(vm.PAEF_NR_ALTURA / 100)), 2);
                    }
                    vm.PAEF_VL_IMC = Convert.ToDecimal(imc);

                    // Prepara data
                    String dataHoje = DateTime.Today.Date.ToLongDateString();
                    if ((Int32)Session["FlagRevisao"] == 0)
                    {
                        dataHoje = "*** Consulta em [" + dataHoje + "] ***";
                    }
                    else
                    {
                        dataHoje = "*** Revisão de Consulta em [" + dataHoje + "] ***";
                    }

                    // Prepara
                    String novo = String.Empty;
