                    Session["IdExameFisico"] = item.PAEF_CD_ID;
                    Session["PacienteAlterada"] = 1;
                    Session["NivelPaciente"] = 6;

                    // Configura serilização
                    JsonSerializerSettings settings = new JsonSerializerSettings
                    {
                        ReferenceLoopHandling = ReferenceLoopHandling.Ignore,
                        NullValueHandling = NullValueHandling.Ignore
                    };

                    // Monta Log
                    DTO_Paciente_Fisico dto = MontarPacienteFisicoDTOObj(item);
                    String json = JsonConvert.SerializeObject(dto, settings);
                    DTO_Paciente_Fisico dtoAntes = MontarPacienteFisicoDTOObj((PACIENTE_EXAME_FISICOS)Session["ExameFisico"]);
                    String jsonAntes = JsonConvert.SerializeObject(dtoAntes, settings);
                    LOG log = new LOG
                    {
                        LOG_DT_DATA = DateTime.Now,
                        ASSI_CD_ID = usuarioLogado.ASSI_CD_ID,
                        USUA_CD_ID = usuarioLogado.USUA_CD_ID,
                        LOG_NM_OPERACAO = "Paciente - Exame Físico - Alteração",
                        LOG_IN_ATIVO = 1,
                        LOG_TX_REGISTRO = json,
                        LOG_TX_REGISTRO_ANTES = jsonAntes,
                        LOG_IN_SISTEMA = 6
                    };
                    Int32 volta1 = logApp.ValidateCreate(log);

                    // Grava historico
                    PACIENTE_EXAME_FISICOS antes1 = (PACIENTE_EXAME_FISICOS)Session["ExameFisico"];
                    if (antes1 != item)
                    {
                        PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                        PACIENTE pac = baseApp.GetItemById(item.PACI_CD_ID);
                        hist.ASSI_CD_ID = usuarioLogado.ASSI_CD_ID;
                        hist.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                        hist.PACI_CD_ID = item.PACI_CD_ID;
                        hist.PAHI_DT_DATA = DateTime.Now;
                        hist.PAHI_IN_TIPO = 9;
                        hist.PAHI_IN_CHAVE = item.PAEF_CD_ID;
                        hist.PAHI_NM_OPERACAO = "Paciente - Alteração de Exame Físico";
                        hist.PAHI_DS_DESCRICAO = "Paciente: " + pac.PACI_NM_NOME.ToUpper() + " - Exame Físico alterado: " + item.PAEF_DT_DATA.Value.ToShortDateString();
                        Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);
                    }

                    // Retornos
                    if ((Int32)Session["VoltaFisico"] == 1)
                    {
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                    else if ((Int32)Session["VoltaFisico"] == 2)
                    {
                        //return RedirectToAction("VoltarEditarUltimoFisico");
                        return RedirectToAction("VoltarProcederConsulta");

                    }
                    return RedirectToAction("VoltarAnexoPaciente");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

