                    vm.PACO_IN_TIPO = area.AREA_IN_TIPO_CONSULTA;
                    vm.PACO_HR_INICIO = area.AREA_HR_INICIO;
                    vm.PACO_HR_FINAL = area.AREA_HR_INICIO.Value.Add(TimeSpan.FromHours(1));
                }
                else
                {
                    vm.PACO_DT_CONSULTA = DateTime.Today.Date;
                    vm.PACO_IN_TIPO = 1;
                }
                vm.USUA_CD_ID = usuario.USUA_CD_ID;
                vm.ASSI_CD_ID = idAss;
                vm.PACO_IN_ENCERRADA = 0;
                vm.PACO_IN_NOVO_PACIENTE = 2;
                vm.PACO_IN_CONFIRMADA = 0;
                vm.PACI_IN_MENOR = 0;
                vm.MODO_CONSULTA = 1;
                vm.DATA_INICIO = DateTime.Today.Date;
                vm.REPETE = 2;
                vm.SEGUNDA_FEIRA = 0;
                vm.TERCA_FEIRA = 0;
                vm.QUARTA_FEIRA = 0;
                vm.QUINTA_FEIRA = 0;
                vm.SEXTA_FEIRA = 0;
                vm.SABADO = 0;
                vm.DOMINGO = 0;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_CONSULTA_INCLUIR", "Paciente", "IncluirConsulta");

                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<ActionResult> IncluirConsulta(PacienteConsultaViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            USUARIO usuario = (USUARIO)Session["UserCredentials"];
            CONFIGURACAO conf = CarregaConfiguracaoGeral();
            Int32 idAss = (Int32)Session["IdAssinante"];
            var tipo = new List<SelectListItem>();
