                            anamnese.PAAM_IN_FLAG_RESPIRATORIO = ana.COAN_IN_RESPIRATORIA;
                            anamnese.PAAM_IN_FLAG_ABDOMEM = ana.COAN_IN_ABDOMEM;
                            anamnese.PAAM_IN_FLAG_MEMBROS_INFERIORES = ana.COAN_IN_MEMBROS;
