                Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);

                // Mensagem do CRUD
                Session["MsgCRUD"] = "A consulta do(a) paciente " + pac.PACI_NM_NOME.ToUpper() + " marcada para " + item.PACO_DT_CONSULTA.ToLongDateString() + " foi confirmada com sucesso";
