        [HttpGet]
        public ActionResult ConfirmarCancelarConsulta()
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_PACIENTE_CONSULTA_ALTERAR == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente - Consulta - Edição";
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Consultas - Confirmação";
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                Int32? diasAntes = conf.CONF_NR_DIAS_CONFIRMACAO;
                ViewBag.NumDias = diasAntes.ToString();
                Int32? verTudo = usuario.PERFIL.PERF_IN_VISAO_GERAL;
                ViewBag.VerTudo = verTudo;

                // Recupera informações
                List<PACIENTE_CONSULTA> cons = new List<PACIENTE_CONSULTA>();
                List<PACIENTE_CONSULTA> hoje = new List<PACIENTE_CONSULTA>();
                List<PACIENTE_CONSULTA> dias = new List<PACIENTE_CONSULTA>();
                if (Session["ListaConfirma"] == null)
                {
                    if (verTudo == 0)
                    {
                        cons = baseApp.GetAllConsultas(idAss).Where(p => p.PACO_IN_ATIVO == 1 & p.PACO_IN_CONFIRMADA < 2 & p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                    }
                    else
                    {
                        cons = baseApp.GetAllConsultas(idAss).Where(p => p.PACO_IN_ATIVO == 1 & p.PACO_IN_CONFIRMADA < 2).ToList();
                    }
                    Session["ListaConfirma"] = cons;
                }
                cons = (List<PACIENTE_CONSULTA>)Session["ListaConfirma"];
                hoje = cons.Where(p => p.PACO_DT_CONSULTA.Date == DateTime.Today.Date).OrderBy(p => p.PACO_DT_CONSULTA).ThenBy(p => p.PACO_HR_INICIO).ToList();
                dias = cons.Where(p => p.PACO_DT_CONSULTA.Date <= DateTime.Today.Date.AddDays(diasAntes.Value) & p.PACO_DT_CONSULTA.Date > DateTime.Today.Date).OrderBy(p => p.PACO_DT_CONSULTA).ThenBy(p => p.PACO_HR_INICIO).ToList();
                ViewBag.Hoje = hoje;
                ViewBag.Dias = dias;

                // Monta demais listas
                var tipo = new List<SelectListItem>();
                tipo.Add(new SelectListItem() { Text = "Presencial", Value = "1" });
                tipo.Add(new SelectListItem() { Text = "Remota", Value = "2" });
                ViewBag.Tipos = new SelectList(tipo, "Value", "Text");
                var conc = new List<SelectListItem>();
                conc.Add(new SelectListItem() { Text = "Confirmada", Value = "1" });
                conc.Add(new SelectListItem() { Text = "Pendente", Value = "0" });
                ViewBag.Confirmada = new SelectList(conc, "Value", "Text");
                ViewBag.Usuario = new SelectList(CarregaUsuario(), "USUA_CD_ID", "USUA_NM_NOME");
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;
                ViewBag.TipoConsulta = new SelectList(CarregaTipoConsulta(), "VACO_CD_ID", "VACO_NM_NOME");

                // Verifica possibilidade E-Mail
                ViewBag.EMail = 1;
                Int32 num = CarregaMensagemEnviada().Where(p => p.MEEN_DT_DATA_ENVIO.Value.Month == DateTime.Today.Date.Month & p.MEEN_DT_DATA_ENVIO.Value.Year == DateTime.Today.Date.Year & p.MEEN_IN_TIPO == 1).ToList().Count;
                if ((Int32)Session["NumEMail"] <= num)
                {
                    ViewBag.EMail = 0;
                }

                // Verifica possibilidade SMS
                ViewBag.SMS = 1;
                num = CarregaMensagemEnviada().Where(p => p.MEEN_DT_DATA_ENVIO.Value.Month == DateTime.Today.Date.Month & p.MEEN_DT_DATA_ENVIO.Value.Year == DateTime.Today.Date.Year & p.MEEN_IN_TIPO == 2).ToList().Count;
                if ((Int32)Session["NumSMS"] <= num)
                {
                    ViewBag.SMS = 0;
                }

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 1)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0016", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 888)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                    if ((Int32)Session["MensPaciente"] == 61)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                }

                // Acerta estado    
                Session["MensPaciente"] = null;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/5/Ajuda5_3.pdf";
                Session["ListaConsultasGeral"] = null;
                Session["VoltaConfirmar"] = 1;
                Session["VoltarEnvio"] = 2;
                Session["VoltaConfirmarCancelar"] = 1;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_CONSULTA_CONFIRMAR", "Paciente", "ConfirmarCancelarConsulta");

                // Carrega view
                objetoConsulta = new PACIENTE_CONSULTA();
                return View(objetoConsulta);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }


