        [HttpGet]
        public ActionResult ProcederConsulta(Int32 id)
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_PACIENTE_CONSULTA_ALTERAR == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente - Consulta - Proceder";
                        return RedirectToAction("VoltarAnexoPaciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                Session["Pisca"] = conf.CONF_IN_PISCA;
                Session["SRF"] = conf.CONF_IN_RECIBO_SRF;
                Session["ModuloAtual"] = "Proceder Consulta";

                // Checa classe
                Int32 classe = 0;
                if (usuario.TICL_CD_ID == null || usuario.TICL_CD_ID == 0 || usuario.USUA_NR_CLASSE == null)
                {
                    classe = 1;
                }
                ViewBag.Classe = classe;


                // Recupera consulta
                Session["NivelPaciente"] = 1;
                PACIENTE_CONSULTA item = baseApp.GetConsultaById(id);
                PacienteConsultaViewModel vm = Mapper.Map<PACIENTE_CONSULTA, PacienteConsultaViewModel>(item);
                Session["IdConsulta"] = item.PACO_CD_ID;

                // Recupera paciente
                PACIENTE pac = baseApp.GetItemById(item.PACI_CD_ID);
                vm.PACI_IN_COMPLETADO = pac.PACI_IN_COMPLETADO;
                ViewBag.TemFicha = pac.PACIENTE_FICHA.Count() > 0 ? 1 : 0;

                // Recupera nome das fichas
                String nomeFicha = String.Empty;
                if (pac.PACI_NR_CPF != null)
                {
                    if (pac.PACI_IN_FICHAS == 1)
                    {
                        nomeFicha = pac.PACI_NM_NOME.ToUpper() + "_" + CrossCutting.ValidarNumerosDocumentos.RemoveNaoNumericos(pac.PACI_NR_CPF) + ".pdf";
                    }
                }
                Session["NomeFicha"] = nomeFicha;
                Session["NomeFicha"] = "../Imagens/" + idAss.ToString() + "/Pacientes/" + pac.PACI__CD_ID.ToString() + "/Fichas/" + nomeFicha;

                // Acerta datas de consulta
                pac.PACI_DT_CONSULTA = item.PACO_DT_CONSULTA;
                pac.PACI_DT_PREVISAO_RETORNO = item.PACO_DT_CONSULTA.AddMonths(6);
                Int32 voltax = baseApp.ValidateEdit(pac, pac);
                PACIENTE paciente = baseApp.GetItemById(pac.PACI__CD_ID);
                Session["IdPaciente"] = paciente.PACI__CD_ID;
                Int32? age = 0;
                if (paciente.PACI_DT_NASCIMENTO != null)
                {
                    age = DateTime.Now.Subtract(paciente.PACI_DT_NASCIMENTO.Value).Days;
                    age = age / 365;
                }

                // Verifica se é consulta ou revisão
                Int32 flagRevisao = 0;
                if (item.PACO_DT_CONSULTA.Date < DateTime.Today.Date)
                {
                    flagRevisao = 1;
                }
                Session["FlagRevisao"] = flagRevisao;

                // Carrega anamnese
                PACIENTE_ANAMNESE anamnese = paciente.PACIENTE_ANAMNESE.Where(p => p.PAAM_IN_ATIVO == 1).FirstOrDefault();
                vm.PAAN_DS_MOTIVO_CONSULTA = anamnese.PAAM_DS_MOTIVO_CONSULTA;
                vm.PAAN_DS_QUEIXA_PRINCIPAL = anamnese.PAAM_DS_QUEIXA_PRINCIPAL;
                vm.PAAN_DS_HISTORIA_FAMILIAR = anamnese.PAAM_DS_HISTORIA_FAMILIAR;
                vm.PAAN_DS_HISTORIA_DOENCA_ATUAL = anamnese.PAAM_DS_HISTORIA_DOENCA_ATUAL;
                vm.PAAN_DS_DIAGNOSTICO_1 = anamnese.PAAM_DS_DIAGNOSTICO_1;
                vm.PAAN_DS_CONDUTA = anamnese.PAAM_DS_CONDUTA;
                vm.PAAM_TX_TEXTO_LIVRE = anamnese.PAAM_TX_TEXTO_LIVRE;
                if (anamnese.PAAM_DT_COPIA != null)
                {
                    vm.PAAN_DT_COPIA = anamnese.PAAM_DT_COPIA.Value;
                }
                vm.PAAM_DS_SONO_PRINCIPAL_QUEIXA = anamnese.PAAM_DS_SONO_PRINCIPAL_QUEIXA;
                vm.PAAM_DS_SONO_SINTOMAS = anamnese.PAAM_DS_SONO_SINTOMAS;
                vm.PAAM_DS_SONO_MEDICAMENTOS = anamnese.PAAM_DS_SONO_MEDICAMENTOS;
                vm.PAAM_DS_SONO_COMORBIDADES = anamnese.PAAM_DS_SONO_COMORBIDADES;

                ViewBag.FlagEdt = paciente.PACI_IN_PADRAO_ANAMNESE;
                Session["FlagEdt"] = paciente.PACI_IN_PADRAO_ANAMNESE;

                // Acerta estado
                Session["IdAnamneseConsulta"] = anamnese.PAAM_CD_ID;
                Session["IdAnamnese"] = anamnese.PAAM_CD_ID;
                Session["EditaAnamnese"] = 1;
                Session["VoltaAnamnese"] = 2;
                Session["VoltaFisico"] = 2;
                Session["ModoConsulta"] = 1;
                Session["VerTodosPaciente"] = 0;
                Session["VoltaListaConsulta"] = 0;
                Session["VoltarPesquisa"] = 0;
                Session["VoltaMail"] = 3;
                Session["TipoSolicitacao"] = 20;
                Session["VoltarExameConsulta"] = 0;
                Session["VoltarAnamnese"] = 2;
                Session["VoltaAnexo"] = 2;
                Session["VoltarEvolucao"] = 2;
                Session["ListaLog"] = null;
                Session["VoltaAnotacaoAnamnese"] = 1;
                Session["NivelPaciente"] = 1;
                ViewBag.VoltaConsulta = 1;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/11/Ajuda11.pdf";
                Session["VoltarProceder"] = 1;
                Session["VoltarConsulta"] = 9;
                Session["VoltaMedico"] = 2;
                Session["TipoMedicoEnvio"] = 2;
                Session["ListaAvisoAtivo"] = null;
                Session["VoltaResposta"] = 3;
                Session["VoltarProceder"] = 1;
                Session["VoltaImpAnamnese"] = 2;
                Session["VoltaAtestado"] = 3;
                Session["VoltaEncerra"] = 1;
                Session["VoltaEncerramento"] = 4;

                // Carrega exame físico
                PACIENTE_EXAME_FISICOS fisico = paciente.PACIENTE_EXAME_FISICOS.Where(p => p.PAEF_IN_ATIVO == 1).ToList().FirstOrDefault();
                vm.PAEF_DT_DATA = fisico.PAEF_DT_DATA;
                vm.PAEF_NR_PA_ALTA = fisico.PAEF_NR_PA_ALTA;
                vm.PAEF_NR_PA_BAIXA = fisico.PAEF_NR_PA_BAIXA;
                vm.PAEF_NR_TEMPERATURA = fisico.PAEF_NR_TEMPERATURA;
                vm.PAEF_NR_FREQUENCIA_CARDIACA = fisico.PAEF_NR_FREQUENCIA_CARDIACA;
                vm.PAEF_NR_PESO = fisico.PAEF_NR_PESO;
                vm.PAEF_NR_ALTURA = fisico.PAEF_NR_ALTURA;
                vm.PAEF_VL_IMC = fisico.PAEF_VL_IMC;
                vm.PAEF_DS_EXAME_FISICO = fisico.PAEF_DS_EXAME_FISICO;
                vm.PAEF_TX_RESULTADOS = fisico.PAEF_TX_RESULTADOS;
                vm.PAEF_DS_FICHA_AVALIACAO = fisico.PAEF_DS_FICHA_AVALIACAO;
                vm.PAEF_NM_TIPO_SANGUE = fisico.PAEF_NM_TIPO_SANGUE;
                vm.Idade = age;
                Session["IdFisicoConsulta"] = fisico.PAEF_CD_ID;
                Session["IdFisico"] = fisico.PAEF_CD_ID;
                Session["EditaFisico"] = 1;

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    // Mensagem
                    if ((Int32)Session["MensPaciente"] == 61)
                    {
                        String msg = (String)Session["MsgCRUD"];
                        ModelState.AddModelError("", msg);
                    }
                    if ((Int32)Session["MensPaciente"] == 62)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0586", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 63)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                    if ((Int32)Session["MensPaciente"] == 5)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0019", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 6)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0024", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 7)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0431", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 12)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0535", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 69)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0539", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 70)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0540", CultureInfo.CurrentCulture));
                    }
                }

                // Verifica consulta a encerrar
                List<PACIENTE_CONSULTA> cons = CarregaConsultas().Where(p => p.PACO_IN_ATIVO == 1).ToList();
                cons = cons.Where(p => p.PACO_DT_CONSULTA.Date < DateTime.Today.Date & p.PACO_IN_CONFIRMADA == 1 & p.PACO_IN_ENCERRADA == 0 & p.PACI_CD_ID == (Int32)Session["IdPaciente"]).ToList();
                Session["TemEncerra"] = cons.Count() > 0 ? 1 : 0;

                if ((Int32)Session["ConsultaMarcada"] == 1)
                {
                    String frase = (String)Session["ConsultaFrase"];
                    TempData["MensagemAcerto"] = frase;
                    TempData["TemMensagem"] = 1;
                }

                // Prepara view
                Session["MensPaciente"] = null;
                Session["ConsultaMarcada"] = 0;
                Session["VoltaImpAnamnese"] = 0;
                objetoAntes = (PACIENTE)Session["Paciente"];
                Session["Consulta"] = item;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_CONSULTA_PROCEDER", "Paciente", "ProcederConsulta");
                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

