        [HttpGet]
        public ActionResult MontarTelaSolicitacoes()
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_SOLICITACAO_ACESSO == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente";
                        return RedirectToAction("MontarTelaPaciente", "Paciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Solicitacoes";
                Session["Solicitacoes"] = null;

                // Carrega listas
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                if (Session["ListaSolicitacoes"] == null)
                {
                    if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                    {
                        listaMasterSolicitacao = CarregaSolicitacoes().Where(p => p.PASO_IN_ATIVO == 1).OrderByDescending(p => p.PASO_DT_EMISSAO).ToList();
                    }
                    else
                    {
                        listaMasterSolicitacao = CarregaSolicitacoes().Where(p => p.PASO_IN_ATIVO == 1 & p.USUA_CD_ID == usuario.USUA_CD_ID).OrderByDescending(p => p.PASO_DT_EMISSAO).ToList();
                    }
                    listaMasterSolicitacao = listaMasterSolicitacao.Where(p => p.PASO_DT_EMISSAO_COMPLETA.Value.Month == DateTime.Today.Month & p.PASO_DT_EMISSAO_COMPLETA.Value.Year == DateTime.Today.Year).ToList();
                    Session["ListaSolicitacoes"] = listaMasterSolicitacao;
                }

                // Checa classe
                Int32 classe = 0;
                if (usuario.TICL_CD_ID == null || usuario.TICL_CD_ID == 0 || usuario.USUA_NR_CLASSE == null)
                {
                    classe = 1;
                }
                ViewBag.Classe = classe;

                // Monta demais listas
                ViewBag.Listas = (List<PACIENTE_SOLICITACAO>)Session["ListaSolicitacoes"];
                ViewBag.Tipos = new SelectList(CarregaTipoExame(), "TIEX_CD_ID", "TIEX_NM_NOME");
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 1)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0016", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 61)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                }

                // Acerta estado
                Session["MensPaciente"] = null;
                Session["VoltaPaciente"] = 1;
                Session["NivelPaciente"] = 1;
                Session["VoltaMsg"] = 0;
                Session["TipoSolicitacao"] = 2;
                Session["ModoConsulta"] = 0;
                Session["VoltarPesquisa"] = 0;
                Session["VoltaMail"] = 2;
                Session["ListaLog"] = null;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/8/Ajuda8.pdf";

                // Carrega view
                objetoSolicitacao = new PACIENTE_SOLICITACAO();

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_SOLICITACAO", "Paciente", "MontarTelaSolicitacoes");
                return View(objetoSolicitacao);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        public ActionResult FiltrarSolicitacoes(PACIENTE_SOLICITACAO item)
        {
            try
            {
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }

                // Sanitização
                item.PASO_NM_TITULO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PASO_NM_TITULO);
                item.PASO_TX_TEXTO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PASO_TX_TEXTO);
                item.PASO_AQ_ARQUIVO_HTML = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PASO_AQ_ARQUIVO_HTML);

                // Executa a operação
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                Int32 idAss = (Int32)Session["IdAssinante"];
                USUARIO usuario = (USUARIO)Session["UserCredentials"];
                List<PACIENTE_SOLICITACAO> listaObj = new List<PACIENTE_SOLICITACAO>();
                Tuple<Int32, List<PACIENTE_SOLICITACAO>, Boolean> volta = baseApp.ExecuteFilterTupleSolicitacao(item.TIEX_CD_ID, item.PASO_AQ_ARQUIVO_HTML, item.PASO_DT_EMISSAO, item.PASO_DT_ENVIO, item.PASO_NM_TITULO, item.PASO_TX_TEXTO, idAss);

                // Verifica retorno
                if (volta.Item1 == 1)
                {
                    Session["MensPaciente"] = 1;
                    return RedirectToAction("MontarTelaSolicitacoes");
                }

                // Sucesso
                listaMasterSolicitacao = volta.Item2.ToList(); ;
                if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                {
                    listaMasterSolicitacao = listaMasterSolicitacao.ToList();
                }
                else
                {
                    listaMasterSolicitacao = listaMasterSolicitacao.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                }
                Session["ListaSolicitacoes"] = listaMasterSolicitacao;
                return RedirectToAction("MontarTelaSolicitacoes");
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

