        [HttpGet]
        public ActionResult MontarTelaAtestados()
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_ATESTADO_ACESSO == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente";
                        return RedirectToAction("MontarTelaPaciente", "Paciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Atestados";

                // Checa classe
                Int32 classe = 0;
                if (usuario.TICL_CD_ID == null || usuario.TICL_CD_ID == 0 || usuario.USUA_NR_CLASSE == null)
                {
                    classe = 1;
                }
                ViewBag.Classe = classe;

                // Carrega listas
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                if (Session["ListaAtestados"] == null)
                {
                    if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                    {
                        listaMasterAtestado = CarregaAtestados().Where(p => p.PAAT_IN_ATIVO == 1).ToList();
                    }
                    else
                    {
                        listaMasterAtestado = CarregaAtestados().Where(p => p.PAAT_IN_ATIVO == 1 & p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                    }
                    listaMasterAtestado = listaMasterAtestado.Where(p => p.PAAT_DT_EMISSAO_COMPLETA.Value.Month == DateTime.Today.Month & p.PAAT_DT_EMISSAO_COMPLETA.Value.Year == DateTime.Today.Year).ToList();
                    Session["ListaAtestados"] = listaMasterAtestado;
                }

                // Monta demais listas
                ViewBag.Listas = (List<PACIENTE_ATESTADO>)Session["ListaAtestados"];
                ViewBag.Tipos = new SelectList(CarregaTipoAtestado(), "TIAT_CD_ID", "TIAT_NM_NOME");
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 1)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0016", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 61)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                }

                // Verifica assinatura digital
                Int32 certificado = 1;
                if (conf.CONF_NM_LOCAL_CERTIFICADO == null || conf.CONF_NM_SENHA_CERTIFICADO == null)
                {
                    certificado = 0;
                }
                String caminhoBase = Server.MapPath("~/Certificados/");
                String pastaCert = Path.Combine(caminhoBase, idAss.ToString());
                String nomeArquivo = conf.CONF_NM_LOCAL_CERTIFICADO;
                String caminhoFinal = Path.Combine(pastaCert, nomeArquivo);
                if (!System.IO.File.Exists(caminhoFinal))
                {
                    certificado = 0;
                }
                Session["TemCertificado"] = certificado;
                Session["VoltaCertificado"] = 1;

                // Acerta estado
                Session["MensPaciente"] = null;
                Session["VoltaPaciente"] = 1;
                Session["NivelPaciente"] = 1;
                Session["VoltaMsg"] = 0;
                Session["TipoSolicitacao"] = 3;
                Session["ModoConsulta"] = 0;
                Session["VoltarPesquisa"] = 0;
                Session["VoltaMail"] = 2;
                Session["VoltarExameConsulta"] = 0;
                Session["ListaLog"] = null;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/7/Ajuda7.pdf";
                ViewBag.VoltaConsulta = 0;

                // Carrega view
                objetoAtestado = new PACIENTE_ATESTADO();

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_ATESTADO", "Paciente", "MontarTelaAtestados");
                return View(objetoAtestado);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        public ActionResult FiltrarAtestados(PACIENTE_ATESTADO item)
        {
            try
            {
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }

                // Sanitização
                item.PAAT_NM_TITULO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PAAT_NM_TITULO);
                item.PAAT_TX_TEXTO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PAAT_TX_TEXTO);
                item.PAAT_AQ_ARQUIVO_HTML = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PAAT_AQ_ARQUIVO_HTML);

                // Executa a operação
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                Int32 idAss = (Int32)Session["IdAssinante"];
                USUARIO usuario = (USUARIO)Session["UserCredentials"];
                List<PACIENTE_ATESTADO> listaObj = new List<PACIENTE_ATESTADO>();
                Tuple<Int32, List<PACIENTE_ATESTADO>, Boolean> volta = baseApp.ExecuteFilterTupleAtestado(item.TIAT_CD_ID, item.PAAT_AQ_ARQUIVO_HTML, item.PAAT_DT_DATA, item.PAAT_DT_ENVIO, item.PAAT_NM_TITULO, item.PAAT_TX_TEXTO, idAss);

                // Verifica retorno
                if (volta.Item1 == 1)
                {
                    Session["MensPaciente"] = 1;
                    return RedirectToAction("MontarTelaAtestados");
                }

                // Sucesso
                listaMasterAtestado = volta.Item2.ToList();
                if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                {
                    listaMasterAtestado = listaMasterAtestado.ToList();
                }
                else
                {
                    listaMasterAtestado = listaMasterAtestado.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                }
                Session["ListaAtestados"] = listaMasterAtestado;
                return RedirectToAction("MontarTelaAtestados");
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

