        [HttpGet]
        public ActionResult MontarTelaExames()
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_EXAME_ACESSO == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente";
                        return RedirectToAction("MontarTelaPaciente", "Paciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Exames";

                // Carrega listas
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                if (Session["ListaExames"] == null)
                {
                    if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                    {
                        listaMasterExame = CarregaExames().Where(p => p.PAEX_IN_ATIVO == 1).ToList();
                    }
                    else
                    {
                        listaMasterExame = CarregaExames().Where(p => p.PAEX_IN_ATIVO == 1 & p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                    }
                    listaMasterExame = listaMasterExame.Where(p => p.PAEX_DT_DATA.Value.Date.Month == DateTime.Today.Date.Month & p.PAEX_DT_DATA.Value.Date.Year == DateTime.Today.Date.Year).ToList();
                    Session["ListaExames"] = listaMasterExame;
                }

                // Monta demais listas
                ViewBag.Listas = (List<PACIENTE_EXAMES>)Session["ListaExames"];
                ViewBag.Tipos = new SelectList(CarregaTipoExame(), "TIEX_CD_ID", "TIEX_NM_NOME");
                ViewBag.Labs = new SelectList(CarregaLaboratorio(), "LABS_CD_ID", "LABS_NM_NOME");
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 1)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0016", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 61)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                }

                // Acerta estado
                Session["MensPaciente"] = null;
                Session["VoltaPaciente"] = 1;
                Session["NivelPaciente"] = 1;
                Session["VoltaMsg"] = 0;
                Session["TipoSolicitacao"] = 4;
                Session["VoltarPesquisa"] = 0;
                Session["ModoConsulta"] = 0;
                Session["VoltarExameConsulta"] = 9;
                Session["AjudaNivel"] = "../BaseAdmin/Ajuda/6/Ajuda6.pdf";
                Session["ListaLog"] = null;

                // Carrega view
                objetoExame = new PACIENTE_EXAMES();

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_EXAME", "Paciente", "MontarTelaExames");
                return View(objetoExame);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        public ActionResult FiltrarExames(PACIENTE_EXAMES item)
        {
            try
            {
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }

                // Sanitização
                item.PAEX_NM_NOME = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PAEX_NM_NOME);
                item.PAEX_DS_COMENTARIOS = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PAEX_DS_COMENTARIOS);
                item.PAEX_DS_DIAGNOSTICO = CrossCutting.UtilitariosGeral.CleanStringGeralNoBreak(item.PAEX_DS_DIAGNOSTICO);

                // Executa a operação
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                Int32 idAss = (Int32)Session["IdAssinante"];
                USUARIO usuario = (USUARIO)Session["UserCredentials"];
                List<PACIENTE_EXAMES> listaObj = new List<PACIENTE_EXAMES>();
                Tuple<Int32, List<PACIENTE_EXAMES>, Boolean> volta = baseApp.ExecuteFilterTupleExame(item.TIEX_CD_ID, item.LABS_CD_ID, item.PAEX_DS_DIAGNOSTICO, item.PAEX_DT_DATA, item.PAEX_DT_DUMMY, item.PAEX_NM_NOME, item.PAEX_DS_COMENTARIOS, idAss);

                // Verifica retorno
                if (volta.Item1 == 1)
                {
                    Session["MensPaciente"] = 1;
                    return RedirectToAction("MontarTelaExames");
                }

                // Sucesso
                listaMasterExame = volta.Item2.ToList();
                if (usuario.PERFIL.PERF_IN_VISAO_GERAL == 1 || usuario.PERFIL.PERF_SG_SIGLA == "ADM")
                {
                    listaMasterExame = listaMasterExame.ToList();
                }
                else
                {
                    listaMasterExame = listaMasterExame.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).ToList();
                }
                Session["ListaExames"] = listaMasterExame;
                return RedirectToAction("MontarTelaExames");
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

