        public ActionResult AcessarLaboratorio(Int32 id)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            LABORATORIO lab = labApp.GetItemById(id);
            String url = lab.LABS_LK_LINK;
            if (!url.Contains("www."))
            {
                url = "www." + url;
            }
            if (!url.Contains("https://"))
            {
                url = "https://" + url;
            }
            return Redirect(url);
        }

        [HttpPost]
        public JsonResult AcessarLaboratorioForm()
        {
            PACIENTE_EXAMES exame = baseApp.GetExameById((Int32)Session["IdExame"]);
            LABORATORIO lab = labApp.GetItemById(exame.LABS_CD_ID.Value);
            String url = lab.LABS_LK_LINK;
            if (!url.Contains("www."))
            {
                url = "www." + url;
            }
            if (!url.Contains("https://"))
            {
                url = "https://" + url;
            }
            return Json(new { success = true, url = url });
        }

