                Int32 voltaX = grava.GravarLogExcecao(ex, "Consulta", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return null;
            }
        }

        [HttpPost]
        public async Task<JsonResult> EditarConsultaOnChange(Int32 id, DateTime data)
        {
            try
            {
                // Recupera dados   
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                CONFIGURACAO_CALENDARIO confCal = CarregaConfiguracaoCalendario();
                USUARIO usuario = (USUARIO)Session["UserCredentials"];
                PACIENTE_CONSULTA vm = baseApp.GetConsultaById(id);
                PacienteConsultaViewModel vmm = Mapper.Map<PACIENTE_CONSULTA, PacienteConsultaViewModel>(vm);
                PACIENTE pac = baseApp.GetItemById(vm.PACI_CD_ID);
                Session["PacienteConsulta"] = pac;
                var hash = new Hashtable();
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["DataOriginal"] = vm.PACO_DT_CONSULTA;

                // Prepara datas
                TimeSpan ini = vm.PACO_HR_INICIO.Value;
                TimeSpan fim = vm.PACO_HR_FINAL.Value;
                TimeSpan difference = fim - ini;
                Double totalHours = difference.TotalHours;
                DateTime dataFim = data.AddHours(totalHours);

                // Critica de data
                if (data.Date < DateTime.Today.Date)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0526", CultureInfo.CurrentCulture));
                    return Json(hash);
                }
                if (vm.PACO_HR_INICIO == vm.PACO_HR_FINAL)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0529", CultureInfo.CurrentCulture));
                    return Json(hash);
                }
                if (vm.PACO_HR_INICIO > vm.PACO_HR_FINAL)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0530", CultureInfo.CurrentCulture));
                    return Json(hash);
                }

                // Critica dia util
                DateTime dataCons = vm.PACO_DT_CONSULTA;
                Int32 dia = (Int32)dataCons.DayOfWeek;
                Int32 voltaCal = VerificacaoDataCalendario.ValidaDiaUtil(dia, confCal);
                if (voltaCal == 1)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0551", CultureInfo.CurrentCulture));
                    return Json(hash);
                }

                // Critica de horario util
                Int32 voltaUtil = VerificacaoDataCalendario.ValidaHoraUtil(dia, vmm, confCal);
                if (voltaUtil == 1)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0552", CultureInfo.CurrentCulture));
                    return Json(hash);
                }
                if (voltaUtil == 2)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0553", CultureInfo.CurrentCulture));
                    return Json(hash);
                }

                // Critica de horario
                List<PACIENTE_CONSULTA> lista = baseApp.GetAllConsultas(idAss).Where(p => p.USUA_CD_ID == vm.USUA_CD_ID & p.PACO_DT_CONSULTA.Date == data.Date & p.PACO_IN_ATIVO == 1 & p.PACO_IN_CONFIRMADA < 2).ToList();
                List<PACIENTE_CONSULTA> lista1 = lista.Where(p => p.PACO_HR_INICIO >= vm.PACO_HR_INICIO & p.PACO_HR_FINAL >= vm.PACO_HR_FINAL & p.PACO_HR_INICIO < vm.PACO_HR_FINAL).ToList();
                List<PACIENTE_CONSULTA> lista2 = lista.Where(p => p.PACO_HR_INICIO <= vm.PACO_HR_INICIO & p.PACO_HR_FINAL >= vm.PACO_HR_FINAL).ToList();
                List<PACIENTE_CONSULTA> lista3 = lista.Where(p => p.PACO_HR_INICIO <= vm.PACO_HR_INICIO & p.PACO_HR_FINAL <= vm.PACO_HR_FINAL & p.PACO_HR_FINAL > vm.PACO_HR_INICIO).ToList();
                List<PACIENTE_CONSULTA> lista4 = lista.Where(p => p.PACO_HR_INICIO >= vm.PACO_HR_INICIO & p.PACO_HR_FINAL <= vm.PACO_HR_FINAL).ToList();
                if (lista1.Count > 0 || lista2.Count > 0 || lista3.Count > 0 || lista4.Count > 0)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0524", CultureInfo.CurrentCulture));
                    return Json(hash);
                }

                // Verifica bloqueios
                List<CONFIGURACAO_CALENDARIO> confs = calApp.GetAllItems(idAss);
                CONFIGURACAO_CALENDARIO cal = null;
                cal = confs.Where(p => p.USUA_CD_ID == usuario.USUA_CD_ID).FirstOrDefault();
                List<CONFIGURACAO_CALENDARIO_BLOQUEIO> bloqs = cal.CONFIGURACAO_CALENDARIO_BLOQUEIO.Where(p => p.COCB_IN_ATIVO == 1).ToList();
                Int32 bloqFlag = 0;
                foreach (CONFIGURACAO_CALENDARIO_BLOQUEIO bloq in bloqs)
                {
                    if (vm.PACO_DT_CONSULTA >= bloq.COCB_DT_BLOQUEIO_INICIO & vm.PACO_DT_CONSULTA <= bloq.COCB_DT_BLOQUEIO_FINAL)
                    {
                        if (bloq.COCB_HR_INICIO == null || bloq.COCB_HR_FINAL == null)
                        {
                            bloqFlag = 1;
                        }
                        else
                        {
                            if (vm.PACO_HR_INICIO >= bloq.COCB_HR_INICIO & vm.PACO_HR_FINAL <= bloq.COCB_HR_FINAL)
                            {
                                bloqFlag = 1;
                            }
                        }
                    }
                }

                if (bloqFlag > 0)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", CRMSys_Base.ResourceManager.GetString("M0565", CultureInfo.CurrentCulture));
                    return Json(hash);
                }

                // Monta novo registro
                PACIENTE_CONSULTA item = new PACIENTE_CONSULTA();
                item.PACO_CD_ID = id;
                item.USUA_CD_ID = vm.USUA_CD_ID;
                item.ASSI_CD_ID = vm.ASSI_CD_ID;
                item.PACO_IN_TIPO = vm.PACO_IN_TIPO;
                item.PACO_HR_INICIO = data.TimeOfDay;
                item.PACO_HR_FINAL = dataFim.TimeOfDay;
                item.PACO_DT_CONSULTA = data.Date;
                item.PACO_IN_ATIVO = 1;
                item.PACI_CD_ID = vm.PACI_CD_ID;
                item.PACO_IN_ENCERRADA = 0;
                item.PACO_IN_CONFIRMADA = 0;
                item.VACO_CD_ID = vm.VACO_CD_ID;
                item.PACO_IN_RECORRENTE = vm.PACO_IN_RECORRENTE;
                item.PACO_IN_RECEBE = vm.PACO_IN_RECEBE;
                item.PACO_TX_JUSTIFICATIVA_CANCELA = vm.PACO_TX_JUSTIFICATIVA_CANCELA;
                Int32 volta = baseApp.ValidateEditConsulta(item);

                // Acerta anamnese
                PACIENTE pac1 = baseApp.GetItemById(item.PACI_CD_ID);
                PACIENTE_ANAMNESE anam = pac1.PACIENTE_ANAMNESE.Where(p => p.PAAM_IN_ATIVO == 1).FirstOrDefault();
                PACIENTE_ANAMNESE anamNova = RemontarAnamnese(anam);
                if (anamNova.PAAM_DT_DATA.Date == ((DateTime)Session["DataOriginal"]).Date)
                {
                    anamNova.PAAM_DT_DATA = item.PACO_DT_CONSULTA;
                    Int32 voltaA = baseApp.ValidateEditAnamnese(anamNova);
                }

                // Acerta paciente
                Int32 voltaP = baseApp.ValidateEdit(pac1, pac1);
                Session["PacienteConsulta"] = pac1;

                // Envia mensagem
                PACIENTE_CONSULTA consMensagem = baseApp.GetConsultaById(item.PACO_CD_ID);
                if (pac1.PACI_NM_EMAIL != null & conf.CONF_IN_MENSAGEM_CONSULTA == 1)
                {
                    Int32 voltaCons = await EnviarEMailConsulta(consMensagem, 2);
                }
                if (usuario.USUA_NM_EMAIL != null)
                {
                    Int32 voltaCons = await EnviarEMailConsulta(consMensagem, 5);
                }

                // Retorno
                if (volta == 0)
                {
                    hash.Add("volta", 1);
                    hash.Add("desc", "Consulta remarcada com sucesso");
                    ((List<PACIENTE_CONSULTA>)Session["ListaAgenda"]).Where(x => x.PACO_CD_ID == id).First().PACO_DT_CONSULTA = data;
                }
                Session["Consultas"] = null;
                Session["ConsultaAlterada"] = 1;
                return Json(hash);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Consulta";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Consulta", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return Json(0);
            }
        }


        public ActionResult ProcessaRelatorioPaciente(Int32? TIPO_RELATORIO)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Login", "ControleAcesso");
            }
            Int32? tipoRel = TIPO_RELATORIO;

            if (tipoRel == 1)
            {
                return RedirectToAction("GerarRelatorioLista");
            }
            if (tipoRel == 2)
            {
                return RedirectToAction("MontarTelaPacienteAtraso");
            }
            if (tipoRel == 3)
            {
                return RedirectToAction("MontarTelaAusencias", "Paciente2");
            }
            return RedirectToAction("MontarTelaCentralPaciente");
        }

