        [HttpPost]
        public ActionResult FiltrarHistoricoGeral(PACIENTE_HISTORICO item)
        {
            try
            {
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }

                // Sanitização
                item.PAHI_NM_OPERACAO = CrossCutting.UtilitariosGeral.CleanStringGeral(item.PAHI_NM_OPERACAO);

                // Executa a operação
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                Int32 idAss = (Int32)Session["IdAssinante"];
                USUARIO usuario = (USUARIO)Session["UserCredentials"];
                List<PACIENTE_HISTORICO> listaObj = new List<PACIENTE_HISTORICO>();
                Tuple<Int32, List<PACIENTE_HISTORICO>, Boolean> volta = baseApp.ExecuteFilterTupleHistoricoGeral(item.PAHI_IN_TIPO, item.PAHI_NM_OPERACAO, item.PAHI_DT_DUMMY, item.PAHI_DT_DUMMY_1, item.PACI_CD_ID, idAss);

                // Verifica retorno
                if (volta.Item1 == 1)
                {
                    Session["MensPaciente"] = 1;
                    return RedirectToAction("MontarTelaHistoricoGeral");
                }

                // Sucesso
                listaMasterHistorico = volta.Item2.OrderByDescending(p => p.PAHI_DT_DATA).ToList();
                Session["ListaHistoricoGeral"] = listaMasterHistorico;
                return RedirectToAction("MontarTelaHistoricoGeral");
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

