                // Recupera informações
                PACIENTE_ATESTADO solic = baseApp.GetAtestadoById((Int32)Session["IdAtestado"]);
                PACIENTE paciente = baseApp.GetItemById(solic.PACI_CD_ID.Value);
                Int32? id = solic.PACI_CD_ID;
