                    {
                        VerticalAlignment = Element.ALIGN_MIDDLE,
                        HorizontalAlignment = Element.ALIGN_LEFT
                    };
                    table.AddCell(cell);
                    numItem++;
                }
                pdfDoc.Add(table);

                // Anotações
                line1 = new Paragraph("  ");
                pdfDoc.Add(line1);

                // Grid
                Chunk chunk4 = new Chunk("Anotações:", FontFactory.GetFont("Arial", 9, Font.BOLD, BaseColor.BLACK));
                pdfDoc.Add(chunk4);

                table = new PdfPTable(new float[] { 70f, 60f, 150f, 500f });
                table.WidthPercentage = 100;
                table.HorizontalAlignment = 0;
                table.SpacingBefore = 1f;
                table.SpacingAfter = 1f;
